import { GoogleGenAI, Type } from "@google/genai";
import { Question } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fetchPYQs(params: {
  count: number;
  subject?: string;
  topic?: string;
  isMix?: boolean;
  testNumber?: number;
  examContext?: string;
}): Promise<Question[]> {
  const { count, subject, topic, isMix, testNumber, examContext } = params;

  // Optimized prompt for high-volume retrieval
  const prompt = `ACT AS A RAJASTHAN EXAM DATABASE EXPERT.
  Task: Retrieve EXACTLY ${count} UNIQUE REAL PREVIOUS YEAR QUESTIONS (PYQs) from RSSB and RPSC official records.

  ${examContext ? `SOURCE: ${examContext}. Provide questions only from this specific official paper.` : `CONTEXT: ${topic || subject || 'Rajasthan GK'} - Practice Set #${testNumber || 1}.`}

  Strict Protocol:
  1. ALL QUESTIONS MUST BE REAL. 
  2. Language: Hindi.
  3. Option E: "अनुत्तरित प्रश्न (Skip Question)".
  4. Marking: Correct answer must be one of A, B, C, D.
  5. JSON Structure must be strictly followed.

  Required JSON Array Format:
  [{
    "id": "pyq_${Date.now()}_[index]",
    "question": "Hindi text",
    "options": {"A":"..","B":"..","C":"..","D":"..","E":"अनुत्तरित प्रश्न"},
    "correctAnswer": "A",
    "examName": "${examContext || 'RSSB/RPSC Exam'}",
    "examYear": 2022,
    "subject": "${subject || 'GK'}"
  }]`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 }, // Disable thinking for maximum speed
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: {
                type: Type.OBJECT,
                properties: {
                  A: { type: Type.STRING },
                  B: { type: Type.STRING },
                  C: { type: Type.STRING },
                  D: { type: Type.STRING },
                  E: { type: Type.STRING },
                },
                required: ['A', 'B', 'C', 'D', 'E']
              },
              correctAnswer: { type: Type.STRING, enum: ['A', 'B', 'C', 'D', 'E'] },
              examName: { type: Type.STRING },
              examYear: { type: Type.NUMBER },
              subject: { type: Type.STRING },
            },
            required: ['id', 'question', 'options', 'correctAnswer', 'examName', 'examYear', 'subject']
          }
        }
      }
    });

    let jsonStr = response.text.trim();
    const parsed = JSON.parse(jsonStr);
    return parsed.slice(0, count); // Ensure we don't exceed requested count
  } catch (error) {
    console.error("Gemini PYQ Fetch Error:", error);
    throw error;
  }
}

import React, { useState, useEffect } from 'react';
import { Question, QuizSession } from '../types';
import { MARKING_SCHEME } from '../constants';

interface QuizEngineProps {
  session: QuizSession;
  onComplete: (session: QuizSession) => void;
  onExit: () => void;
  isReview?: boolean;
}

const QuizEngine: React.FC<QuizEngineProps> = ({ session, onComplete, onExit, isReview = false }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>>(session.userAnswers);
  const [timeLeft, setTimeLeft] = useState(session.durationInMinutes * 60);

  useEffect(() => {
    if (isReview) return;
    if (timeLeft <= 0) {
      handleSubmit();
      return;
    }
    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isReview]);

  const handleSubmit = () => {
    onComplete({
      ...session,
      userAnswers: answers,
      completed: true
    });
  };

  const handleBackClick = () => {
    if (isReview) {
      onExit();
      return;
    }
    if (window.confirm("क्या आप टेस्ट से बाहर निकलना चाहते हैं? (Are you sure you want to exit?)")) {
      onExit();
    }
  };

  const handleSelect = (option: 'A' | 'B' | 'C' | 'D' | 'E') => {
    if (isReview) return;
    const qId = session.questions[currentIdx].id;
    setAnswers(prev => ({ ...prev, [qId]: option }));
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const currentQ = session.questions[currentIdx];
  const userAns = answers[currentQ.id];

  return (
    <div className="flex flex-col lg:flex-row gap-6 max-w-[1400px] mx-auto animate-fadeIn">
      {/* Main Content Area */}
      <div className="flex-grow">
        <div className="glass sticky top-16 md:top-20 z-40 px-4 py-3 rounded-2xl shadow-sm border border-slate-200 mb-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-black text-xs whitespace-nowrap">
              Q {currentIdx + 1} / {session.questions.length}
            </span>
            {!isReview && (
              <div className={`flex items-center gap-1 font-mono text-lg font-bold ${timeLeft < 300 ? 'text-rose-600 animate-pulse' : 'text-slate-700'}`}>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                {formatTime(timeLeft)}
              </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             {isReview ? (
               <button onClick={onExit} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold text-sm hover:bg-slate-900 transition-all">Exit Review</button>
             ) : (
               <>
                <button onClick={handleSubmit} className="bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold text-sm hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100">Submit</button>
                <div className="h-6 w-px bg-slate-200"></div>
                <button 
                  onClick={handleBackClick}
                  className="flex items-center gap-2 text-slate-400 hover:text-rose-600 font-black transition-colors text-xs uppercase tracking-widest group"
                >
                  <span>Quit</span>
                  <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7" />
                  </svg>
                </button>
               </>
             )}
          </div>
        </div>

        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 md:p-12 mb-6">
          <div className="flex flex-wrap items-center gap-3 mb-8">
            <span className="bg-blue-600 text-white text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest">
              {currentQ.examName}
            </span>
            <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1.5 rounded-full border border-slate-200 uppercase">
              {currentQ.subject} • {currentQ.examYear}
            </span>
          </div>

          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-10 leading-relaxed hindi-text">
            {currentQ.question}
          </h2>

          <div className="grid gap-4">
            {(['A', 'B', 'C', 'D', 'E'] as const).map((key) => {
              const isSelected = userAns === key;
              const isCorrect = key === currentQ.correctAnswer;
              const isE = key === 'E';

              let styles = 'border-slate-100 hover:border-blue-200 hover:bg-slate-50';
              if (isReview) {
                if (isCorrect) styles = 'bg-emerald-50 border-emerald-500 ring-4 ring-emerald-500/10';
                else if (isSelected && !isCorrect) styles = 'bg-rose-50 border-rose-500 ring-4 ring-rose-500/10';
              } else if (isSelected) {
                styles = 'bg-blue-50 border-blue-600 ring-4 ring-blue-600/10';
              }

              return (
                <button
                  key={key}
                  disabled={isReview}
                  onClick={() => handleSelect(key)}
                  className={`group w-full flex items-center p-5 rounded-2xl border-2 transition-all text-left ${styles}`}
                >
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black mr-5 shrink-0 transition-all ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                    {key}
                  </div>
                  <div className="flex-grow">
                     <span className={`text-lg font-bold ${isSelected ? 'text-blue-900' : 'text-slate-700'} ${isE ? 'text-sm italic opacity-60 font-medium' : 'hindi-text'}`}>
                        {currentQ.options[key]}
                     </span>
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
          <button
            disabled={currentIdx === 0}
            onClick={() => setCurrentIdx(prev => prev - 1)}
            className="px-6 py-3 rounded-xl font-black border-2 border-slate-100 text-slate-400 disabled:opacity-30 hover:bg-slate-50 transition-all text-sm flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
            PREV
          </button>

          <div className="hidden sm:flex gap-1.5">
             {session.questions.map((_, idx) => (
                <div key={idx} className={`h-1.5 transition-all rounded-full ${idx === currentIdx ? 'w-8 bg-blue-600' : 'w-1.5 bg-slate-200'}`}></div>
             ))}
          </div>

          <button
            onClick={() => {
              if (currentIdx < session.questions.length - 1) {
                setCurrentIdx(prev => prev + 1);
              } else if (!isReview) {
                handleSubmit();
              } else {
                onExit();
              }
            }}
            className="px-8 py-3 rounded-xl font-black bg-blue-600 text-white hover:bg-blue-700 transition-all text-sm flex items-center gap-2 shadow-lg shadow-blue-100"
          >
            {currentIdx === session.questions.length - 1 ? (isReview ? 'EXIT' : 'SUBMIT') : 'NEXT'}
            {currentIdx !== session.questions.length - 1 && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>}
          </button>
        </div>
      </div>

      <div className="w-full lg:w-80 shrink-0">
        <div className="bg-white rounded-[2rem] p-8 border border-slate-100 sticky top-24 shadow-sm">
          <h3 className="text-xs font-black text-slate-400 mb-6 uppercase tracking-[0.2em]">Quick Jump</h3>
          <div className="grid grid-cols-5 gap-2 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
            {session.questions.map((q, idx) => {
              const isAnswered = !!answers[q.id];
              const isCurrent = idx === currentIdx;

              let status = 'bg-slate-50 text-slate-300 border-transparent';
              if (isCurrent) status = 'bg-blue-600 text-white border-blue-600 scale-110 shadow-lg shadow-blue-100';
              else if (isAnswered) status = 'bg-emerald-50 text-emerald-600 border-emerald-100 font-black';

              return (
                <button
                  key={idx}
                  onClick={() => setCurrentIdx(idx)}
                  className={`aspect-square rounded-xl border-2 flex items-center justify-center font-bold text-xs transition-all ${status}`}
                >
                  {idx + 1}
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default QuizEngine;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  AttemptRecord
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME 
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadProgress, setLoadProgress] = useState(0);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [completedTests, setCompletedTests] = useState<Set<string>>(new Set());
  const [testHistory, setTestHistory] = useState<AttemptRecord[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setView(AppView.HOME);
    }
    const savedProgress = localStorage.getItem('rajquiz_progress');
    if (savedProgress) {
      try { setCompletedTests(new Set(JSON.parse(savedProgress))); } catch (e) { console.error(e); }
    }
    const savedHistory = localStorage.getItem('rajquiz_history');
    if (savedHistory) {
      try { setTestHistory(JSON.parse(savedHistory)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    setLoginError('');
  }, [authStep]);

  // Loading Progress Simulation
  useEffect(() => {
    if (loading) {
      setLoadProgress(0);
      const interval = setInterval(() => {
        setLoadProgress(prev => {
          if (prev >= 95) return prev;
          return prev + (prev < 60 ? 10 : 2);
        });
      }, 400);
      return () => clearInterval(interval);
    }
  }, [loading]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { setLoginError("यह नंबर रजिस्टर्ड नहीं है।"); return; }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);
      setView(AppView.HOME);
      setPassword('');
    } else { setLoginError("गलत पासवर्ड!"); }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) return alert("10 अंकों का नंबर डालें");
    if (password !== confirmPassword) return; 
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) return alert("यह नंबर पहले से है।");
    users[phone] = { password };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    alert("अकाउंट बन गया! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
  };

  const handleLogout = () => {
    if (window.confirm("लॉगआउट करना चाहते हैं?")) {
      localStorage.removeItem('rajquiz_currentUser');
      setIsLoggedIn(false);
      setView(AppView.AUTH);
      setAuthStep(AuthSubView.CHOICE);
    }
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    const testId = options.testId || `${type}-${title.replace(/\s+/g, '_')}-${options.testNumber || 1}`;
    const cached = localStorage.getItem(`qcache_${testId}`);

    if (cached) {
      const q = JSON.parse(cached);
      setActiveSession({
        type, title, questions: q, currentQuestionIndex: 0, 
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count === 100 ? 120 : 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      localStorage.setItem(`qcache_${testId}`, JSON.stringify(questions));
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count === 100 ? 120 : 60, completed: false
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("नेटवर्क एरर। दोबारा कोशिश करें।");
    } finally {
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: QuizSession) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach(q => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const results = { score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, session };
    setLastResults(results as any);
    navigateTo(AppView.SCORECARD);
  };

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center p-4">
      <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-50">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-8">
            <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter text-blue-600 italic">RAJQUIZER.</h2>
              <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.3em] mt-2">Premium Exam Portal</p>
            </div>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 transition-all hover:bg-blue-700 active:scale-95">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg transition-all hover:bg-slate-800 active:scale-95">SIGN UP</button>
            </div>
          </div>
        ) : (
          <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-4">
            <h3 className="text-3xl font-black mb-2 tracking-tight">{authStep === AuthSubView.LOGIN ? 'Welcome Back' : 'Create Account'}</h3>
            <p className="text-slate-400 text-sm mb-6">{authStep === AuthSubView.LOGIN ? 'Login to continue your preparation.' : 'Join 10,000+ students today.'}</p>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="Phone Number" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />
            {authStep === AuthSubView.SIGNUP && <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold transition-all" required />}
            {loginError && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest ml-1">{loginError}</p>}
            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 mt-4 transition-all hover:bg-blue-700">Continue</button>
            <button type="button" onClick={() => setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN)} className="w-full py-2 text-blue-600 font-black text-xs uppercase tracking-widest mt-4">Switch to {authStep === AuthSubView.LOGIN ? 'Sign Up' : 'Login'}</button>
          </form>
        )}
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="space-y-12 animate-fadeIn max-w-6xl mx-auto py-8">
      <div className="text-center space-y-4">
        <h1 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic">READY FOR <span className="text-blue-600">SELECTION?</span></h1>
        <p className="text-slate-500 font-bold text-lg md:text-xl max-w-2xl mx-auto opacity-70">Official RSSB & RPSC Previous Year Question Database (2015-2026).</p>
      </div>
      <div className="grid md:grid-cols-3 gap-8">
        {[
          { title: "Mixed Mocks", view: AppView.QUIZ_MIX_MENU, gradient: "from-blue-600 to-indigo-900", desc: "200 Random practice sets." },
          { title: "Topic Wise", view: AppView.QUIZ_TOPIC_MENU, gradient: "from-emerald-500 to-teal-900", desc: "History, Geo, Culture, Polity." },
          { title: "Exam Tests", view: AppView.EXAM_MENU, gradient: "from-slate-800 to-slate-950", desc: "Original 2022-24 Exam Papers." }
        ].map(card => (
          <button key={card.title} onClick={() => navigateTo(card.view)} className={`p-10 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group overflow-hidden relative`}>
            <div className="relative z-10">
              <h3 className="text-3xl font-black mb-3 uppercase tracking-tighter">{card.title}</h3>
              <p className="text-white/60 font-bold text-sm leading-relaxed mb-8">{card.desc}</p>
              <div className="flex items-center gap-2 text-white font-black uppercase text-[10px] tracking-widest">Open Section <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderExamMenu = () => {
    const exams = [
      { name: "Lab Assistant 2022 (Paper-1: GK)", year: 2022, context: "Official Lab Assistant 2022 Paper 1 General Knowledge", count: 100, tag: "100 Qs" },
      { name: "Lab Assistant 2022 (Paper-2: Science)", year: 2022, context: "Official Lab Assistant 2022 Paper 2 Science Subject", count: 100, tag: "100 Qs" },
      { name: "CET Graduate Level 2024", year: 2024, context: "CET Graduate Level 2024 Official Paper", count: 50, tag: "Full Mock" },
      { name: "LDC Exam 2024", year: 2024, context: "LDC 2024 Exam Official Shift 1", count: 50, tag: "Real Paper" },
      { name: "RAS Pre 2023", year: 2023, context: "RAS Prelims 2023 Official Paper", count: 50, tag: "Premium" },
      { name: "VDO Pre 2021", year: 2021, context: "VDO 2021 Official Question Bank", count: 50, tag: "Official" }
    ];

    return (
      <div className="space-y-10 animate-fadeIn max-w-6xl mx-auto py-6">
        <div className="flex items-center gap-6">
          <button onClick={() => navigateTo(AppView.HOME)} className="bg-white p-3 rounded-2xl border-2 border-slate-100 text-slate-400 hover:text-blue-600 transition-all group">
