          const n = i + 1;
          return (
            <button key={n} onClick={() => startQuiz(QuizType.MIX, `Set #${n}`, { testNumber: n, isMix: true })} className="p-6 bg-white border-2 border-slate-100 rounded-3xl flex items-center justify-between hover:border-blue-600 hover:shadow-xl transition-all group">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-900 text-white rounded-2xl flex items-center justify-center font-black transition-all group-hover:bg-blue-600">{n}</div>
                <div className="text-left"><h4 className="font-black text-lg">Practice Set {n}</h4><p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">25 Questions • 60 Mins</p></div>
              </div>
              <svg className="w-6 h-6 text-slate-200 group-hover:text-blue-600 group-hover:translate-x-1 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
            </button>
