      <div className="grid md:grid-cols-2 gap-8">
        {TOPIC_GROUPS.map(g => (
          <button key={g.id} onClick={() => { setSelectedGroup(g); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="p-12 bg-white border-2 border-slate-100 rounded-[3.5rem] text-left hover:border-emerald-600 hover:shadow-2xl transition-all group relative overflow-hidden">
            <div className="relative z-10">
              <h3 className="text-3xl font-black mb-2 uppercase tracking-tighter">{g.name}</h3>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">{g.subtopics.length} Sub-Categories</p>
