        <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="bg-white p-3 rounded-2xl border-2 border-slate-100 text-slate-400 hover:text-blue-600 transition-all group">
            <svg className="w-6 h-6 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <h2 className="text-3xl font-black uppercase tracking-tighter italic">{selectedGroup?.name}</h2>
