        {selectedGroup?.subtopics.map(s => (
          <button key={s} onClick={() => { setSelectedSubtopic(s); navigateTo(AppView.QUIZ_TOPIC_TESTS_MENU); }} className="p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] text-left hover:bg-slate-50 hover:border-emerald-600 transition-all hindi-text font-bold text-xl flex items-center justify-between group">
