         <h2 className="text-4xl md:text-5xl font-black tracking-tighter uppercase italic leading-tight">{selectedSubtopic}</h2>
      </div>
      <div className="grid md:grid-cols-2 gap-10">
        {[1, 2].map(num => (
          <button key={num} onClick={() => startQuiz(QuizType.TOPIC, `Practice Set ${num}`, { topic: selectedSubtopic, testNumber: num })} className="p-12 bg-white border-2 border-slate-100 rounded-[3.5rem] hover:border-emerald-600 hover:shadow-2xl transition-all group flex flex-col items-center text-center">
            <div className="w-24 h-24 bg-emerald-600 text-white rounded-[2rem] flex items-center justify-center font-black text-4xl mb-8 group-hover:scale-110 shadow-lg shadow-emerald-100 transition-all">{num}</div>
            <h3 className="text-2xl font-black uppercase tracking-tighter mb-2">Practice Set {num}</h3>
            <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">25 Topic-Specific Questions</p>
            <div className="mt-10 px-10 py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all shadow-md">Launch Now</div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="max-w-2xl mx-auto py-12">
      <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100">
        <div className="flex items-center gap-6 mb-12">
          <div className="w-20 h-20 bg-blue-600 rounded-[2rem] flex items-center justify-center text-white text-3xl font-black shadow-xl shadow-blue-100">R</div>
          <div>
            <h2 className="text-4xl font-black tracking-tighter">{phone}</h2>
            <div className="flex items-center gap-2 mt-2">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              <span className="text-slate-400 text-xs font-black uppercase tracking-widest">Premium Portal Active</span>
            </div>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-6 mb-12">
            <div className="bg-slate-50 p-8 rounded-[2.5rem] text-center">
              <div className="text-4xl font-black text-slate-900">{completedTests.size}</div>
              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Tests Completed</div>
            </div>
            <div className="bg-slate-50 p-8 rounded-[2.5rem] text-center">
              <div className="text-4xl font-black text-slate-900">{testHistory.length}</div>
              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Total Attempts</div>
            </div>
        </div>
        <button onClick={handleLogout} className="w-full py-5 bg-rose-50 text-rose-600 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all hover:bg-rose-600 hover:text-white">Logout Account</button>
      </div>
    </div>
  );

  return (
    <Layout onHomeClick={() => navigateTo(AppView.HOME)} onProfileClick={() => navigateTo(AppView.PROFILE)} onLogout={handleLogout} isLoggedIn={isLoggedIn}>
      {loading ? (
        <div className="min-h-[60vh] flex flex-col items-center justify-center animate-fadeIn px-8">
          <div className="relative w-32 h-32 mb-12">
            <div className="absolute inset-0 border-[12px] border-slate-100 rounded-full"></div>
            <div className="absolute inset-0 border-[12px] border-blue-600 rounded-full border-t-transparent animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center font-black text-blue-600 text-2xl">{loadProgress}%</div>
          </div>
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-black uppercase tracking-tighter italic animate-pulse">Accessing Database</h2>
            <p className="text-slate-400 font-bold text-sm uppercase tracking-widest max-w-sm">Fetching real Previous Year Questions from RSSB & RPSC records...</p>
          </div>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.QUIZ_MIX_MENU && renderMixMenu()}
          {view === AppView.QUIZ_TOPIC_MENU && renderTopicMenu()}
          {view === AppView.QUIZ_SUBTOPIC_MENU && renderSubtopicMenu()}
          {view === AppView.QUIZ_TOPIC_TESTS_MENU && renderTopicTestsMenu()}
          {view === AppView.PROFILE && renderProfile()}
          {view === AppView.EXAM_MENU && renderExamMenu()}
          {view === AppView.QUIZ_ACTIVE && activeSession && <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />}
          {view === AppView.SCORECARD && lastResults && <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />}
          {view === AppView.REVIEW && lastResults && <QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />}
        </>
      )}
    </Layout>
  );
};

export default App;

