               <div className="grid md:grid-cols-3 gap-6 px-4">
                 {OFFICIAL_EXAMS.map((exam, i) => (
                   <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { examContext: exam.context, count: exam.count })} className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-50 hover:border-blue-600 transition-all text-left group">
                     <div className="flex justify-between mb-4">
                        <span className="text-[10px] font-black text-slate-400">{exam.year}</span>
                        <span className="bg-blue-50 text-blue-600 text-[10px] font-black px-2 py-0.5 rounded-full">{exam.tag}</span>
                     </div>
                     <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-6">{exam.name}</h3>
                     <div className="text-xs font-bold text-slate-400">{exam.count} Questions</div>
