import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadProgress, setLoadProgress] = useState(0);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [examFilter, setExamFilter] = useState<string>('All');

  // Progress tracking: key is test unique ID, value is percentage
  const [userProgress, setUserProgress] = useState<Record<string, number>>({});

  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setPhone(savedUser);
      setView(AppView.HOME);

      // Load progress for this specific user
      const progressKey = `rajquiz_progress_${savedUser}`;
      const savedProgress = localStorage.getItem(progressKey);
      if (savedProgress) {
        try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
      }
    }
  }, []);

  const saveProgress = (testKey: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testKey]: Math.max(userProgress[testKey] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { setLoginError("नंबर पंजीकृत नहीं है।"); return; }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);

      const progressKey = `rajquiz_progress_${phone}`;
      const savedProgress = localStorage.getItem(progressKey);
      if (savedProgress) {
        try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { setUserProgress({}); }
      }

      navigateTo(AppView.HOME);
    } else { setLoginError("पासवर्ड गलत है।"); }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) return alert("सही मोबाइल नंबर दर्ज करें");
    if (password !== confirmPassword) return alert("पासवर्ड मैच नहीं हुए");
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) return alert("यह नंबर पहले से पंजीकृत है।");
    users[phone] = { password };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    alert("पंजीकरण सफल! अब लॉगिन करें।");
    setAuthStep(AuthSubView.LOGIN);
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    setLoadProgress(0);
    const progInt = setInterval(() => {
      setLoadProgress(p => p >= 90 ? p : p + 5);
    }, 150);

    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 60, completed: false,
        testId: options.testId // Pass through unique ID for progress tracking
      } as any);
      setLoadProgress(100);
      setTimeout(() => navigateTo(AppView.QUIZ_ACTIVE), 300);
    } catch (err) {
      alert("प्रश्न प्राप्त करने में समस्या आई।");
    } finally {
      clearInterval(progInt);
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });

    const totalQuestions = session.questions.length;
    const maxScore = totalQuestions * 2;
    const percentage = Math.max(0, (score / maxScore) * 100);

    // Save progress if session has a testId
    if (session.testId) {
      saveProgress(session.testId, percentage);
    }

    setLastResults({ 
      score, 
      correctCount: correct, 
      incorrectCount: incorrect, 
      skippedCount: skipped, 
      unattemptedCount: unattempted, 
      totalQuestions, 
      session 
    } as any);
    navigateTo(AppView.SCORECARD);
  };

  const filteredExams = useMemo(() => {
    if (examFilter === 'All') return OFFICIAL_EXAMS;
    return OFFICIAL_EXAMS.filter(e => e.category === examFilter);
  }, [examFilter]);

  const examCategories = useMemo(() => {
    const cats = new Set(OFFICIAL_EXAMS.map(e => e.category));
    return ['All', ...Array.from(cats)];
  }, []);

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center">
      <div className="bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-100">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-10">
            <h2 className="text-4xl font-black text-blue-600 italic tracking-tighter">RAJQUIZER.</h2>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all">SIGN UP</button>
            </div>
          </div>
        ) : (
          <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-4">
            <h3 className="text-3xl font-black">{authStep === AuthSubView.LOGIN ? 'Welcome' : 'Join Us'}</h3>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="Mobile Number" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            {authStep === AuthSubView.SIGNUP && <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />}
            {loginError && <p className="text-rose-500 text-xs font-black uppercase ml-1">{loginError}</p>}
            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 mt-4">Continue</button>
            <button type="button" onClick={() => setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN)} className="w-full py-2 text-blue-600 font-bold text-xs uppercase tracking-widest mt-2">Switch</button>
          </form>
        )}
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="space-y-16 animate-fadeIn max-w-6xl mx-auto py-10">
      <div className="text-center space-y-4">
        <h1 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">TARGET <span className="text-blue-600">SELECTION.</span></h1>
        <p className="text-slate-500 font-bold text-lg md:text-xl opacity-70">Complete Rajasthan Exam PYQ Database 2015-2026.</p>
      </div>
      <div className="grid md:grid-cols-3 gap-8 px-4">
        {[
          { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-blue-600 to-indigo-900", desc: "Original RSSB & RPSC Papers." },
          { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-emerald-500 to-teal-800", desc: "History, Geo, Culture, Polity." },
          { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Practice Question Sets." }
        ].map(card => (
          <button key={card.title} onClick={card.onClick} className={`p-10 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group`}>
            <h3 className="text-3xl font-black mb-2 uppercase">{card.title}</h3>
            <p className="text-white/60 font-bold text-sm mb-8">{card.desc}</p>
            <div className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">Explore <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const handleLogout = () => {
    localStorage.removeItem('rajquiz_currentUser');
    setIsLoggedIn(false);
    setUserProgress({});
    navigateTo(AppView.AUTH);
    setAuthStep(AuthSubView.CHOICE);
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onTopicTestsClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)}
      onExamPapersClick={() => navigateTo(AppView.EXAM_MENU)}
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout}
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="min-h-[60vh] flex flex-col items-center justify-center animate-fadeIn px-8">
          <div className="relative w-32 h-32 mb-10">
            <div className="absolute inset-0 border-[10px] border-slate-100 rounded-full"></div>
            <div className="absolute inset-0 border-[10px] border-blue-600 rounded-full border-t-transparent animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center font-black text-blue-600 text-2xl">{loadProgress}%</div>
          </div>
          <h2 className="text-3xl font-black uppercase italic tracking-tighter">Preparing Questions...</h2>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl animate-fadeIn text-center">
              <div className="w-24 h-24 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white text-3xl font-black mb-6 uppercase">
                {phone.slice(0, 1)}
              </div>
              <h2 className="text-3xl font-black mb-2">{phone}</h2>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-[0.2em] mb-12">Portal Member Since 2025</p>
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-6 rounded-2xl">
                    <div className="text-2xl font-black">{Object.keys(userProgress).length}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Tests Completed</div>
                 </div>
                 <div className="bg-slate-50 p-6 rounded-2xl">
                    <div className="text-2xl font-black">10K+</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total PYQs</div>
                 </div>
              </div>
            </div>
          )}
          {view === AppView.EXAM_MENU && (
             <div className="space-y-10 animate-fadeIn max-w-6xl mx-auto py-6 px-4">
               <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10">
                  <div>
                    <h2 className="text-4xl font-black uppercase italic">Official Exam Papers</h2>
                    <p className="text-slate-400 font-bold text-sm mt-2 uppercase tracking-widest">Targeted practice for RPSC/RSSB</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {examCategories.map(cat => (
                      <button 
                        key={cat} 
                        onClick={() => setExamFilter(cat)}
                        className={`px-5 py-2.5 rounded-full text-xs font-black uppercase tracking-widest transition-all border-2 ${examFilter === cat ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'}`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
               </div>

               <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {filteredExams.map((exam, i) => {
                   const testId = `exam_${exam.name}_${exam.year}`;
                   const score = userProgress[testId];
                   const isDone = score !== undefined;

                   return (
                     <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: exam.count })} className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all text-left group relative overflow-hidden ${isDone ? 'border-emerald-100' : 'border-slate-50 hover:border-blue-600'}`}>
                       {isDone && (
                          <div className="absolute top-4 right-4 bg-emerald-500 text-white p-1 rounded-full shadow-lg shadow-emerald-100">
                             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                          </div>
                       )}
                       <div className="flex justify-between mb-4">
                          <span className="text-[10px] font-black text-slate-400">{exam.year}</span>
                          <span className="bg-blue-50 text-blue-600 text-[10px] font-black px-2 py-0.5 rounded-full">{exam.tag}</span>
                       </div>
                       <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-6">{exam.name}</h3>
                       <div className="flex items-center justify-between">
                          <div className="flex flex-col">
                            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">{exam.count} Questions</div>
                            {isDone && <div className="text-xs font-black text-emerald-600 mt-1">Score: {score.toFixed(1)}%</div>}
                          </div>
                          <div className="text-[10px] font-black text-blue-600 opacity-0 group-hover:opacity-100 transition-opacity uppercase">Start Test →</div>
                       </div>
                     </button>
                   );
                 })}
               </div>
             </div>
          )}
          {view === AppView.QUIZ_TOPIC_MENU && (
             <div className="space-y-10 animate-fadeIn max-w-4xl mx-auto py-6">
                <h2 className="text-4xl font-black uppercase italic px-4">Topics Wise Tests</h2>
                <div className="grid gap-4 px-4">
                  {TOPIC_GROUPS.map(g => (
                    <button key={g.id} onClick={() => { setSelectedGroup(g); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="p-10 bg-white border-2 border-slate-50 rounded-[2.5rem] text-left hover:border-emerald-600 transition-all flex items-center justify-between group">
                      <div>
                        <h3 className="text-2xl font-black uppercase group-hover:text-emerald-600 transition-colors">{g.name}</h3>
                        <p className="text-slate-400 font-bold text-xs uppercase mt-1">{g.subtopics.length} Categories</p>
                      </div>
                      <svg className="w-6 h-6 text-slate-200 group-hover:text-emerald-600 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                    </button>
                  ))}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_SUBTOPIC_MENU && (
             <div className="space-y-6 animate-fadeIn max-w-3xl mx-auto py-6">
                <div className="flex items-center gap-4 px-4 mb-6">
                  <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-2 bg-slate-100 rounded-lg text-slate-500 hover:bg-slate-200">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
                  </button>
                  <h2 className="text-2xl font-black italic">{selectedGroup?.name}</h2>
                </div>
                <div className="grid gap-3 px-4">
                  {selectedGroup?.subtopics.map(s => {
                    const testId = `topic_${s}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;

                    return (
                      <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { testId, topic: s })} className={`p-6 bg-white border-2 transition-all hindi-text font-bold text-lg rounded-2xl text-left flex items-center justify-between group ${isDone ? 'border-emerald-100 bg-emerald-50/20' : 'border-slate-50 hover:bg-emerald-50 hover:border-emerald-600'}`}>
                        <div className="flex flex-col">
                           <span>{s}</span>
                           {isDone && <span className="text-xs font-black text-emerald-600 mt-1 uppercase tracking-widest font-sans">Best Score: {score.toFixed(1)}%</span>}
                        </div>
                        {isDone && (
                           <div className="bg-emerald-500 text-white p-1 rounded-full">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                           </div>
                        )}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_MIX_MENU && (
             <div className="space-y-8 animate-fadeIn max-w-6xl mx-auto py-6">
                <h2 className="text-4xl font-black uppercase italic px-4">Mixed Mocks (1-200)</h2>
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 px-4 h-[600px] overflow-y-auto custom-scrollbar">
                  {Array.from({ length: 200 }).map((_, i) => {
                    const testId = `mix_set_${i+1}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;

                    return (
                      <button key={i} onClick={() => startQuiz(QuizType.MIX, `Set #${i+1}`, { testId, testNumber: i+1 })} className={`p-4 rounded-xl border transition-all font-bold flex flex-col items-center justify-center relative ${isDone ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-white border-slate-100 hover:bg-slate-900 hover:text-white'}`}>
                        <span>Set #{i+1}</span>
                        {isDone && (
                           <>
                             <div className="text-[10px] font-black mt-1">{score.toFixed(0)}%</div>
                             <div className="absolute top-1 right-1">
                                <svg className="w-3 h-3 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                             </div>
                           </>
                        )}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_ACTIVE && activeSession && <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />}
          {view === AppView.SCORECARD && lastResults && <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />}
          {view === AppView.REVIEW && lastResults && <QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Question, QuizSession } from '../types.ts';
import { MARKING_SCHEME } from '../constants.ts';

interface QuizEngineProps {
  session: QuizSession;
  onComplete: (session: QuizSession) => void;
  onExit: () => void;
  isReview?: boolean;
}

const QuizEngine: React.FC<QuizEngineProps> = ({ session, onComplete, onExit, isReview = false }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>>(session.userAnswers);
  const [timeLeft, setTimeLeft] = useState(session.durationInMinutes * 60);

  useEffect(() => {
    if (isReview) return;
    if (timeLeft <= 0) {
      handleSubmit();
      return;
    }
    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isReview]);

  const handleSubmit = () => {
    onComplete({
      ...session,
      userAnswers: answers,
      completed: true
    });
  };

  const handleBackClick = () => {
    if (isReview) {
      onExit();
      return;
    }
    if (window.confirm("क्या आप टेस्ट से बाहर निकलना चाहते हैं? (Are you sure you want to exit?)")) {
      onExit();
    }
  };

  const handleSelect = (option: 'A' | 'B' | 'C' | 'D' | 'E') => {
    if (isReview) return;
    const qId = session.questions[currentIdx].id;
    setAnswers(prev => ({ ...prev, [qId]: option }));
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const currentQ = session.questions[currentIdx];
  const userAns = answers[currentQ.id];

  return (
    <div className="flex flex-col lg:flex-row gap-6 max-w-[1400px] mx-auto animate-fadeIn">
      {/* Main Content Area */}
      <div className="flex-grow">
        <div className="glass sticky top-16 md:top-20 z-40 px-4 py-3 rounded-2xl shadow-sm border border-slate-200 mb-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-black text-xs whitespace-nowrap">
              Q {currentIdx + 1} / {session.questions.length}
            </span>
            {!isReview && (
              <div className={`flex items-center gap-1 font-mono text-lg font-bold ${timeLeft < 300 ? 'text-rose-600 animate-pulse' : 'text-slate-700'}`}>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                {formatTime(timeLeft)}
              </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             {isReview ? (
               <button onClick={onExit} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold text-sm hover:bg-slate-900 transition-all">Exit Review</button>
             ) : (
               <>
                <button onClick={handleSubmit} className="bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold text-sm hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100">Submit</button>
                <div className="h-6 w-px bg-slate-200"></div>
                <button 
                  onClick={handleBackClick}
                  className="flex items-center gap-2 text-slate-400 hover:text-rose-600 font-black transition-colors text-xs uppercase tracking-widest group"
                >
                  <span>Quit</span>
                  <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7" />
                  </svg>
                </button>
               </>
             )}
          </div>
        </div>

        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 md:p-12 mb-6">
          <div className="flex flex-wrap items-center gap-3 mb-8">
            <span className="bg-blue-600 text-white text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest">
              {currentQ.examName}
            </span>
            <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1.5 rounded-full border border-slate-200 uppercase">
              {currentQ.subject} • {currentQ.examYear}
            </span>
          </div>

          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-10 leading-relaxed hindi-text">
            {currentQ.question}
          </h2>

          <div className="grid gap-4">
            {(['A', 'B', 'C', 'D', 'E'] as const).map((key) => {
              const isSelected = userAns === key;
              const isCorrect = key === currentQ.correctAnswer;
              const isE = key === 'E';

              let styles = 'border-slate-100 hover:border-blue-200 hover:bg-slate-50';
              if (isReview) {
                if (isCorrect) styles = 'bg-emerald-50 border-emerald-500 ring-4 ring-emerald-500/10';
                else if (isSelected && !isCorrect) styles = 'bg-rose-50 border-rose-500 ring-4 ring-rose-500/10';
              } else if (isSelected) {
                styles = 'bg-blue-50 border-blue-600 ring-4 ring-blue-600/10';
              }

              return (
                <button
                  key={key}
                  disabled={isReview}
                  onClick={() => handleSelect(key)}
                  className={`group w-full flex items-center p-5 rounded-2xl border-2 transition-all text-left ${styles}`}
                >
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black mr-5 shrink-0 transition-all ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                    {key}
                  </div>
                  <div className="flex-grow">
                     <span className={`text-lg font-bold ${isSelected ? 'text-blue-900' : 'text-slate-700'} ${isE ? 'text-sm italic opacity-60 font-medium' : 'hindi-text'}`}>
                        {currentQ.options[key]}
                     </span>
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
          <button
            disabled={currentIdx === 0}
            onClick={() => setCurrentIdx(prev => prev - 1)}
            className="px-6 py-3 rounded-xl font-black border-2 border-slate-100 text-slate-400 disabled:opacity-30 hover:bg-slate-50 transition-all text-sm flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
            PREV
          </button>

          <div className="hidden sm:flex gap-1.5">
             {session.questions.map((_, idx) => (
                <div key={idx} className={`h-1.5 transition-all rounded-full ${idx === currentIdx ? 'w-8 bg-blue-600' : 'w-1.5 bg-slate-200'}`}></div>
             ))}
          </div>

          <button
            onClick={() => {
              if (currentIdx < session.questions.length - 1) {
                setCurrentIdx(prev => prev + 1);
              } else if (!isReview) {
                handleSubmit();
              } else {
                onExit();
              }
            }}
            className="px-8 py-3 rounded-xl font-black bg-blue-600 text-white hover:bg-blue-700 transition-all text-sm flex items-center gap-2 shadow-lg shadow-blue-100"
          >
            {currentIdx === session.questions.length - 1 ? (isReview ? 'EXIT' : 'SUBMIT') : 'NEXT'}
            {currentIdx !== session.questions.length - 1 && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>}
          </button>
        </div>
      </div>

      <div className="w-full lg:w-80 shrink-0">
        <div className="bg-white rounded-[2rem] p-8 border border-slate-100 sticky top-24 shadow-sm">
          <h3 className="text-xs font-black text-slate-400 mb-6 uppercase tracking-[0.2em]">Quick Jump</h3>
          <div className="grid grid-cols-5 gap-2 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
            {session.questions.map((q, idx) => {
              const isAnswered = !!answers[q.id];
              const isCurrent = idx === currentIdx;

              let status = 'bg-slate-50 text-slate-300 border-transparent';
              if (isCurrent) status = 'bg-blue-600 text-white border-blue-600 scale-110 shadow-lg shadow-blue-100';
              else if (isAnswered) status = 'bg-emerald-50 text-emerald-600 border-emerald-100 font-black';

              return (
                <button
                  key={idx}
                  onClick={() => setCurrentIdx(idx)}
                  className={`aspect-square rounded-xl border-2 flex items-center justify-center font-bold text-xs transition-all ${status}`}
                >
                  {idx + 1}
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default QuizEngine;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.tsx';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadProgress, setLoadProgress] = useState(0);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [examFilter, setExamFilter] = useState<string>('All');

  // Progress tracking: key is test unique ID, value is percentage
  const [userProgress, setUserProgress] = useState<Record<string, number>>({});

  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      setIsLoggedIn(true);
      setPhone(savedUser);
      setView(AppView.HOME);

      // Load progress for this specific user
      const progressKey = `rajquiz_progress_${savedUser}`;
      const savedProgress = localStorage.getItem(progressKey);
      if (savedProgress) {
        try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
      }
    }
  }, []);

  const saveProgress = (testKey: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testKey]: Math.max(userProgress[testKey] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { 
      setLoginError("यह नंबर पंजीकृत नहीं है। कृपया पहले साइनअप करें।"); 
      return; 
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      setIsLoggedIn(true);

      const progressKey = `rajquiz_progress_${phone}`;
      const savedProgress = localStorage.getItem(progressKey);
      if (savedProgress) {
        try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { setUserProgress({}); }
      }

      navigateTo(AppView.HOME);
      setLoginError('');
    } else { 
      setLoginError("पासवर्ड गलत है।"); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();

    // Check if signup is restricted or encountering issues
    // As per user request: if signup isn't working, show message and redirect to login
    try {
      if (phone.length < 10) {
        setLoginError("सही मोबाइल नंबर दर्ज करें");
        return;
      }
      if (password !== confirmPassword) {
        setLoginError("पासवर्ड मैच नहीं हुए");
        return;
      }

      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      if (users[phone]) {
        setLoginError("यह नंबर पहले से पंजीकृत है। कृपया लॉगिन करें।");
        setAuthStep(AuthSubView.LOGIN);
        return;
      }

      // Simulate potential failure point
      // If we wanted to "disable" signup, we'd throw here
      users[phone] = { password };
      localStorage.setItem('rajquiz_users', JSON.stringify(users));

      alert("पंजीकरण सफल! अब लॉगिन करें।");
      setAuthStep(AuthSubView.LOGIN);
      setLoginError('');
    } catch (err) {
      setLoginError("साइनअप अभी काम नहीं कर रहा है (Signup not working). कृपया सीधे लॉगिन करें।");
      setAuthStep(AuthSubView.LOGIN);
    }
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    setLoadProgress(0);
    const progInt = setInterval(() => {
      setLoadProgress(p => p >= 90 ? p : p + 5);
    }, 150);

    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 60, completed: false,
        testId: options.testId // Pass through unique ID for progress tracking
      } as any);
      setLoadProgress(100);
      setTimeout(() => navigateTo(AppView.QUIZ_ACTIVE), 300);
    } catch (err) {
      alert("प्रश्न प्राप्त करने में समस्या आई।");
    } finally {
      clearInterval(progInt);
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });

    const totalQuestions = session.questions.length;
    const maxScore = totalQuestions * 2;
    const percentage = Math.max(0, (score / maxScore) * 100);

    // Save progress if session has a testId
    if (session.testId) {
      saveProgress(session.testId, percentage);
    }

    setLastResults({ 
      score, 
      correctCount: correct, 
      incorrectCount: incorrect, 
      skippedCount: skipped, 
      unattemptedCount: unattempted, 
      totalQuestions, 
      session 
    } as any);
    navigateTo(AppView.SCORECARD);
  };

  const filteredExams = useMemo(() => {
    if (examFilter === 'All') return OFFICIAL_EXAMS;
    return OFFICIAL_EXAMS.filter(e => e.category === examFilter);
  }, [examFilter]);

  const examCategories = useMemo(() => {
    const cats = new Set(OFFICIAL_EXAMS.map(e => e.category));
    return ['All', ...Array.from(cats)];
  }, []);

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center">
      <div className="bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-100">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-10">
            <h2 className="text-4xl font-black text-blue-600 italic tracking-tighter">RAJQUIZER.</h2>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all">SIGN UP</button>
            </div>
          </div>
        ) : (
          <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-4">
            <h3 className="text-3xl font-black">{authStep === AuthSubView.LOGIN ? 'Welcome' : 'Join Us'}</h3>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="Mobile Number" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            {authStep === AuthSubView.SIGNUP && <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />}

            {loginError && (
              <div className="bg-rose-50 border border-rose-100 p-4 rounded-xl">
                <p className="text-rose-600 text-[11px] font-black uppercase leading-tight">{loginError}</p>
              </div>
            )}

            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 mt-4">Continue</button>
            <button type="button" onClick={() => {
                setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN);
                setLoginError('');
              }} 
              className="w-full py-2 text-blue-600 font-bold text-xs uppercase tracking-widest mt-2">
              {authStep === AuthSubView.LOGIN ? 'Create Account' : 'Back to Login'}
            </button>
          </form>
        )}
      </div>
    </div>
  );

  const renderHome = () => (
    <div className="space-y-16 animate-fadeIn max-w-6xl mx-auto py-10">
      <div className="text-center space-y-4">
        <h1 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">TARGET <span className="text-blue-600">SELECTION.</span></h1>
        <p className="text-slate-500 font-bold text-lg md:text-xl opacity-70">Complete Rajasthan Exam PYQ Database 2015-2026.</p>
      </div>
      <div className="grid md:grid-cols-3 gap-8 px-4">
        {[
          { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-blue-600 to-indigo-900", desc: "Original RSSB & RPSC Papers." },
          { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-emerald-500 to-teal-800", desc: "History, Geo, Culture, Polity." },
          { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Practice Question Sets." }
        ].map(card => (
          <button key={card.title} onClick={card.onClick} className={`p-10 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group`}>
            <h3 className="text-3xl font-black mb-2 uppercase">{card.title}</h3>
            <p className="text-white/60 font-bold text-sm mb-8">{card.desc}</p>
            <div className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">Explore <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
          </button>
        ))}
      </div>
    </div>
  );

  const handleLogout = () => {
    localStorage.removeItem('rajquiz_currentUser');
    setIsLoggedIn(false);
    setUserProgress({});
    navigateTo(AppView.AUTH);
    setAuthStep(AuthSubView.CHOICE);
    setLoginError('');
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onTopicTestsClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)}
      onExamPapersClick={() => navigateTo(AppView.EXAM_MENU)}
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout}
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="min-h-[60vh] flex flex-col items-center justify-center animate-fadeIn px-8">
          <div className="relative w-32 h-32 mb-10">
            <div className="absolute inset-0 border-[10px] border-slate-100 rounded-full"></div>
            <div className="absolute inset-0 border-[10px] border-blue-600 rounded-full border-t-transparent animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center font-black text-blue-600 text-2xl">{loadProgress}%</div>
          </div>
          <h2 className="text-3xl font-black uppercase italic tracking-tighter">Preparing Questions...</h2>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && renderHome()}
          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl animate-fadeIn text-center">
              <div className="w-24 h-24 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white text-3xl font-black mb-6 uppercase">
                {phone.slice(0, 1)}
              </div>
              <h2 className="text-3xl font-black mb-2">{phone}</h2>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-[0.2em] mb-12">Portal Member Since 2025</p>
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-50 p-6 rounded-2xl">
                    <div className="text-2xl font-black">{Object.keys(userProgress).length}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Tests Completed</div>
                 </div>
                 <div className="bg-slate-50 p-6 rounded-2xl">
                    <div className="text-2xl font-black">10K+</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total PYQs</div>
                 </div>
              </div>
            </div>
          )}
          {view === AppView.EXAM_MENU && (
             <div className="space-y-10 animate-fadeIn max-w-6xl mx-auto py-6 px-4">
               <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10">
                  <div>
                    <h2 className="text-4xl font-black uppercase italic">Official Exam Papers</h2>
                    <p className="text-slate-400 font-bold text-sm mt-2 uppercase tracking-widest">Targeted practice for RPSC/RSSB</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {examCategories.map(cat => (
                      <button 
                        key={cat} 
                        onClick={() => setExamFilter(cat)}
                        className={`px-5 py-2.5 rounded-full text-xs font-black uppercase tracking-widest transition-all border-2 ${examFilter === cat ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-100' : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'}`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
               </div>

               <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {filteredExams.map((exam, i) => {
                   const testId = `exam_${exam.name}_${exam.year}`;
                   const score = userProgress[testId];
                   const isDone = score !== undefined;

                   return (
                     <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: exam.count })} className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all text-left group relative overflow-hidden ${isDone ? 'border-emerald-100' : 'border-slate-50 hover:border-blue-600'}`}>
                       {isDone && (
                          <div className="absolute top-4 right-4 bg-emerald-500 text-white p-1 rounded-full shadow-lg shadow-emerald-100">
                             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                          </div>
                       )}
                       <div className="flex justify-between mb-4">
                          <span className="text-[10px] font-black text-slate-400">{exam.year}</span>
                          <span className="bg-blue-50 text-blue-600 text-[10px] font-black px-2 py-0.5 rounded-full">{exam.tag}</span>
                       </div>
                       <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-6">{exam.name}</h3>
                       <div className="flex items-center justify-between">
                          <div className="flex flex-col">
                            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">{exam.count} Questions</div>
                            {isDone && <div className="text-xs font-black text-emerald-600 mt-1">Score: {score.toFixed(1)}%</div>}
                          </div>
                          <div className="text-[10px] font-black text-blue-600 opacity-0 group-hover:opacity-100 transition-opacity uppercase">Start Test →</div>
                       </div>
                     </button>
                   );
                 })}
               </div>
             </div>
          )}
          {view === AppView.QUIZ_TOPIC_MENU && (
             <div className="space-y-10 animate-fadeIn max-w-4xl mx-auto py-6">
                <h2 className="text-4xl font-black uppercase italic px-4">Topics Wise Tests</h2>
                <div className="grid gap-4 px-4">
                  {TOPIC_GROUPS.map(g => (
                    <button key={g.id} onClick={() => { setSelectedGroup(g); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="p-10 bg-white border-2 border-slate-50 rounded-[2.5rem] text-left hover:border-emerald-600 transition-all flex items-center justify-between group">
                      <div>
                        <h3 className="text-2xl font-black uppercase group-hover:text-emerald-600 transition-colors">{g.name}</h3>
                        <p className="text-slate-400 font-bold text-xs uppercase mt-1">{g.subtopics.length} Categories</p>
                      </div>
                      <svg className="w-6 h-6 text-slate-200 group-hover:text-emerald-600 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                    </button>
                  ))}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_SUBTOPIC_MENU && (
             <div className="space-y-6 animate-fadeIn max-w-3xl mx-auto py-6">
                <div className="flex items-center gap-4 px-4 mb-6">
                  <button onClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)} className="p-2 bg-slate-100 rounded-lg text-slate-500 hover:bg-slate-200">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
                  </button>
                  <h2 className="text-2xl font-black italic">{selectedGroup?.name}</h2>
                </div>
                <div className="grid gap-3 px-4">
                  {selectedGroup?.subtopics.map(s => {
                    const testId = `topic_${s}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;

                    return (
                      <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { testId, topic: s })} className={`p-6 bg-white border-2 transition-all hindi-text font-bold text-lg rounded-2xl text-left flex items-center justify-between group ${isDone ? 'border-emerald-100 bg-emerald-50/20' : 'border-slate-50 hover:bg-emerald-50 hover:border-emerald-600'}`}>
                        <div className="flex flex-col">
                           <span>{s}</span>
                           {isDone && <span className="text-xs font-black text-emerald-600 mt-1 uppercase tracking-widest font-sans">Best Score: {score.toFixed(1)}%</span>}
                        </div>
                        {isDone && (
                           <div className="bg-emerald-500 text-white p-1 rounded-full">
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                           </div>
                        )}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_MIX_MENU && (
             <div className="space-y-8 animate-fadeIn max-w-6xl mx-auto py-6">
                <h2 className="text-4xl font-black uppercase italic px-4">Mixed Mocks (1-200)</h2>
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 px-4 h-[600px] overflow-y-auto custom-scrollbar">
                  {Array.from({ length: 200 }).map((_, i) => {
                    const testId = `mix_set_${i+1}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;

                    return (
                      <button key={i} onClick={() => startQuiz(QuizType.MIX, `Set #${i+1}`, { testId, testNumber: i+1 })} className={`p-4 rounded-xl border transition-all font-bold flex flex-col items-center justify-center relative ${isDone ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-white border-slate-100 hover:bg-slate-900 hover:text-white'}`}>
                        <span>Set #{i+1}</span>
                        {isDone && (
                           <>
                             <div className="text-[10px] font-black mt-1">{score.toFixed(0)}%</div>
                             <div className="absolute top-1 right-1">
                                <svg className="w-3 h-3 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                             </div>
                           </>
                        )}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_ACTIVE && activeSession && <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} />}
          {view === AppView.SCORECARD && lastResults && <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />}
          {view === AppView.REVIEW && lastResults && <QuizEngine session={lastResults.session} onComplete={() => {}} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} />}
        </>
      )}
    </Layout>
  );
};

export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  QUIZ_TOPIC_TESTS_MENU = 'quiz_topic_tests_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review',
  PROFILE = 'profile',
  BOOKMARKS = 'bookmarks'
}

export enum AuthSubView {
  CHOICE = 'choice',
  LOGIN = 'login',
  SIGNUP = 'signup',
  FORGOT_PHONE = 'forgot_phone',
  FORGOT_OTP = 'forgot_otp',
  RESET_PASSWORD = 'reset_password'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
  testId?: string;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

export interface AttemptRecord {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  date: number;
  correct: number;
  total: number;
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [examFilter, setExamFilter] = useState<string>('All');

  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      loginUser(savedUser);
    }
  }, []);

  const loginUser = (userPhone: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setView(AppView.HOME);

    // Load progress
    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    // Load bookmarks
    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testKey: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testKey]: Math.max(userProgress[testKey] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];

    if (!user) { 
      setLoginError("यह नंबर पंजीकृत नहीं है। हमने आपको साइनअप पेज पर भेज दिया है।"); 
      setAuthStep(AuthSubView.SIGNUP);
      return; 
    }

    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone);
      setLoginError('');
    } else { 
      setLoginError("पासवर्ड गलत है।"); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (phone.length < 10) {
        setLoginError("सही मोबाइल नंबर दर्ज करें");
        return;
      }
      if (password !== confirmPassword) {
        setLoginError("पासवर्ड मैच नहीं हुए");
        return;
      }

      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      users[phone] = { password };
      localStorage.setItem('rajquiz_users', JSON.stringify(users));

      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone);
      setLoginError('');
    } catch (err) {
      setLoginError("साइनअप अभी काम नहीं कर रहा है। कृपया सीधे लॉगिन करें।");
      setAuthStep(AuthSubView.LOGIN);
    }
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    try {
      // Immediate fetch - removed artificial progress intervals for "instant" feel
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 60, completed: false,
        testId: options.testId
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("प्रश्न प्राप्त करने में समस्या आई।");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });

    const totalQuestions = session.questions.length;
    const maxScore = totalQuestions * 2;
    const percentage = Math.max(0, (score / maxScore) * 100);

    if (session.testId) {
      saveProgress(session.testId, percentage);
    }

    setLastResults({ 
      score, correctCount: correct, incorrectCount: incorrect, 
      skippedCount: skipped, unattemptedCount: unattempted, 
      totalQuestions, session 
    } as any);
    navigateTo(AppView.SCORECARD);
  };

  const filteredExams = useMemo(() => {
    if (examFilter === 'All') return OFFICIAL_EXAMS;
    return OFFICIAL_EXAMS.filter(e => e.category === examFilter);
  }, [examFilter]);

  const examCategories = useMemo(() => {
    const cats = new Set(OFFICIAL_EXAMS.map(e => e.category));
    return ['All', ...Array.from(cats)];
  }, []);

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center">
      <div className="bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-100">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-10">
            <h2 className="text-4xl font-black text-blue-600 italic tracking-tighter">RAJQUIZER.</h2>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all">SIGN UP</button>
            </div>
          </div>
        ) : (
          <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-4">
            <h3 className="text-3xl font-black">{authStep === AuthSubView.LOGIN ? 'Welcome' : 'Join Us'}</h3>
            <input type="tel" value={phone} autoComplete="tel" onChange={e => setPhone(e.target.value)} placeholder="Mobile Number" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            <input type="password" value={password} autoComplete="current-password" onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            {authStep === AuthSubView.SIGNUP && <input type="password" value={confirmPassword} autoComplete="new-password" onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />}

            {loginError && (
              <div className="bg-rose-50 border border-rose-100 p-4 rounded-xl">
                <p className="text-rose-600 text-[11px] font-black uppercase leading-tight">{loginError}</p>
              </div>
            )}

            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 mt-4 transition-transform active:scale-95">Continue</button>
            <button type="button" onClick={() => {
                setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN);
                setLoginError('');
              }} 
              className="w-full py-2 text-blue-600 font-bold text-xs uppercase tracking-widest mt-2">
              {authStep === AuthSubView.LOGIN ? 'Create Account' : 'Back to Login'}
            </button>
          </form>
        )}
      </div>
    </div>
  );

  const renderBookmarks = () => (
    <div className="max-w-4xl mx-auto py-10 animate-fadeIn">
      <div className="flex items-center justify-between mb-10 px-4">
        <h2 className="text-4xl font-black uppercase italic">Bookmarked PYQs</h2>
        <span className="bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-black">{bookmarks.length} Saved</span>
      </div>

      {bookmarks.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-[3.5rem] border-2 border-dashed border-slate-200">
           <p className="text-slate-400 font-bold text-lg">No bookmarked questions yet.</p>
           <button onClick={() => navigateTo(AppView.HOME)} className="mt-4 text-blue-600 font-black uppercase text-xs tracking-widest">Explore Tests →</button>
        </div>
      ) : (
        <div className="space-y-6 px-4">
          {bookmarks.map((q, idx) => (
            <div key={q.id} className="bg-white p-8 rounded-[2.5rem] shadow-lg border border-slate-100 relative group">
               <button 
                onClick={() => toggleBookmark(q)} 
                className="absolute top-6 right-6 text-rose-500 hover:scale-110 transition-transform"
               >
                 <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/></svg>
               </button>
               <div className="flex gap-2 mb-4">
                  <span className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 px-2 py-1 rounded">{q.examName}</span>
                  <span className="text-[10px] font-black uppercase text-slate-400 bg-slate-50 px-2 py-1 rounded">{q.examYear}</span>
               </div>
               <p className="text-xl font-bold hindi-text leading-relaxed mb-6">{q.question}</p>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-3 opacity-60">
                 {['A','B','C','D'].map(key => (
                   <div key={key} className={`p-3 rounded-xl border ${key === q.correctAnswer ? 'bg-emerald-50 border-emerald-200' : 'bg-slate-50 border-slate-100'}`}>
                     <span className="font-black mr-2">{key}.</span>
                     <span className="hindi-text">{(q.options as any)[key]}</span>
                   </div>
                 ))}
               </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  const handleLogout = () => {
    localStorage.removeItem('rajquiz_currentUser');
    setIsLoggedIn(false);
    setUserProgress({});
    setBookmarks([]);
    navigateTo(AppView.AUTH);
    setAuthStep(AuthSubView.CHOICE);
    setLoginError('');
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onTopicTestsClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)}
      onExamPapersClick={() => navigateTo(AppView.EXAM_MENU)}
      onBookmarksClick={() => navigateTo(AppView.BOOKMARKS)}
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout}
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="min-h-[60vh] flex flex-col items-center justify-center animate-fadeIn">
          <div className="relative w-20 h-20 mb-6">
            <div className="absolute inset-0 border-4 border-slate-100 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
          </div>
          <h2 className="text-xl font-black uppercase tracking-tighter text-slate-400">Loading PYQs...</h2>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && (
             <div className="space-y-16 animate-fadeIn max-w-6xl mx-auto py-10">
               <div className="text-center space-y-4">
                 <h1 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">TARGET <span className="text-blue-600">SELECTION.</span></h1>
                 <p className="text-slate-500 font-bold text-lg md:text-xl opacity-70">Complete Rajasthan Exam PYQ Database 2015-2026.</p>
               </div>
               <div className="grid md:grid-cols-3 gap-8 px-4">
                 {[
                   { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-blue-600 to-indigo-900", desc: "Original RSSB & RPSC Papers." },
                   { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-emerald-500 to-teal-800", desc: "History, Geo, Culture, Polity." },
                   { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Practice Question Sets." }
                 ].map(card => (
                   <button key={card.title} onClick={card.onClick} className={`p-10 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group active:scale-95`}>
                     <h3 className="text-3xl font-black mb-2 uppercase">{card.title}</h3>
                     <p className="text-white/60 font-bold text-sm mb-8">{card.desc}</p>
                     <div className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">Explore <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
                   </button>
                 ))}
               </div>
             </div>
          )}
          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl animate-fadeIn text-center">
              <div className="w-24 h-24 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white text-3xl font-black mb-6 uppercase">
                {phone.slice(0, 1)}
              </div>
              <h2 className="text-3xl font-black mb-2">{phone}</h2>
              <div className="grid grid-cols-3 gap-4 mt-12">
                 <div className="bg-slate-50 p-6 rounded-2xl">
                    <div className="text-2xl font-black">{Object.keys(userProgress).length}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Solved</div>
                 </div>
                 <div className="bg-slate-50 p-6 rounded-2xl cursor-pointer" onClick={() => navigateTo(AppView.BOOKMARKS)}>
                    <div className="text-2xl font-black">{bookmarks.length}</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Bookmarks</div>
                 </div>
                 <div className="bg-slate-50 p-6 rounded-2xl">
                    <div className="text-2xl font-black">10K+</div>
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total</div>
                 </div>
              </div>
            </div>
          )}
          {view === AppView.EXAM_MENU && (
             <div className="space-y-10 animate-fadeIn max-w-6xl mx-auto py-6 px-4">
               <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10">
                  <div>
                    <h2 className="text-4xl font-black uppercase italic">Official Exam Papers</h2>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {examCategories.map(cat => (
                      <button key={cat} onClick={() => setExamFilter(cat)} className={`px-5 py-2.5 rounded-full text-xs font-black uppercase tracking-widest transition-all border-2 ${examFilter === cat ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-400'}`}>
                        {cat}
                      </button>
                    ))}
                  </div>
               </div>
               <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {filteredExams.map((exam, i) => {
                   const testId = `exam_${exam.name}_${exam.year}`;
                   const score = userProgress[testId];
                   const isDone = score !== undefined;
                   return (
                     <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: exam.count })} className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all text-left group relative overflow-hidden ${isDone ? 'border-emerald-100' : 'border-slate-50 hover:border-blue-600'}`}>
                       {isDone && <div className="absolute top-4 right-4 bg-emerald-500 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg></div>}
                       <div className="flex justify-between mb-4">
                          <span className="text-[10px] font-black text-slate-400">{exam.year}</span>
                       </div>
                       <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-6">{exam.name}</h3>
                       <div className="flex items-center justify-between">
                          <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">{exam.count} Questions</div>
                          {isDone && <div className="text-xs font-black text-emerald-600">Score: {score.toFixed(1)}%</div>}
                       </div>
                     </button>
                   );
                 })}
               </div>
             </div>
          )}
          {view === AppView.QUIZ_TOPIC_MENU && (
