import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);

  // Enhanced filtering state
  const [examSearch, setExamSearch] = useState('');
  const [selectedExamCategories, setSelectedExamCategories] = useState<string[]>(['All']);

  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      loginUser(savedUser);
    }
  }, []);

  const loginUser = (userPhone: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setView(AppView.HOME);

    // Load progress
    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    // Load bookmarks
    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testKey: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testKey]: Math.max(userProgress[testKey] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];

    if (!user) { 
      setLoginError("यह नंबर पंजीकृत नहीं है। हमने आपको साइनअप पेज पर भेज दिया है।"); 
      setAuthStep(AuthSubView.SIGNUP);
      return; 
    }

    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone);
      setLoginError('');
    } else { 
      setLoginError("पासवर्ड गलत है।"); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (phone.length < 10) {
        setLoginError("सही मोबाइल नंबर दर्ज करें");
        return;
      }
      if (password !== confirmPassword) {
        setLoginError("पासवर्ड मैच नहीं हुए");
        return;
      }

      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      users[phone] = { password };
      localStorage.setItem('rajquiz_users', JSON.stringify(users));

      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone);
      setLoginError('');
    } catch (err) {
      setLoginError("साइनअप अभी काम नहीं कर रहा है। कृपया सीधे लॉगिन करें।");
      setAuthStep(AuthSubView.LOGIN);
    }
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 60, completed: false,
        testId: options.testId
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("प्रश्न प्राप्त करने में समस्या आई।");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });

    const totalQuestions = session.questions.length;
    const maxScore = totalQuestions * 2;
    const percentage = Math.max(0, (score / maxScore) * 100);

    if (session.testId) {
      saveProgress(session.testId, percentage);
    }

    setLastResults({ 
      score, correctCount: correct, incorrectCount: incorrect, 
      skippedCount: skipped, unattemptedCount: unattempted, 
      totalQuestions, session 
    } as any);
    navigateTo(AppView.SCORECARD);
  };

  const filteredExams = useMemo(() => {
    return OFFICIAL_EXAMS.filter(exam => {
      const matchesSearch = exam.name.toLowerCase().includes(examSearch.toLowerCase()) || 
                            exam.category.toLowerCase().includes(examSearch.toLowerCase());
      const matchesCategory = selectedExamCategories.includes('All') || 
                              selectedExamCategories.includes(exam.category);
      return matchesSearch && matchesCategory;
    });
  }, [examSearch, selectedExamCategories]);

  const examCategories = useMemo(() => {
    const cats = new Set(OFFICIAL_EXAMS.map(e => e.category));
    return ['All', ...Array.from(cats)];
  }, []);

  const toggleCategory = (cat: string) => {
    if (cat === 'All') {
      setSelectedExamCategories(['All']);
      return;
    }

    let next = selectedExamCategories.filter(c => c !== 'All');
    if (next.includes(cat)) {
      next = next.filter(c => c !== cat);
      if (next.length === 0) next = ['All'];
    } else {
      next = [...next, cat];
    }
    setSelectedExamCategories(next);
  };

  const renderBackButton = (target: AppView = AppView.HOME) => (
    <button 
      onClick={() => navigateTo(target)}
      className="mb-6 flex items-center gap-2 text-slate-400 font-black hover:text-blue-600 transition-colors uppercase tracking-widest text-xs group"
    >
      <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
      </svg>
      Back
    </button>
  );

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center">
      <div className="bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-100">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-10">
            <h2 className="text-4xl font-black text-blue-600 italic tracking-tighter">RAJQUIZER.</h2>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all">SIGN UP</button>
            </div>
          </div>
        ) : (
          <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-4">
            <div className="flex items-center gap-2 mb-2">
               <button type="button" onClick={() => setAuthStep(AuthSubView.CHOICE)} className="text-slate-400 hover:text-blue-600"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7"/></svg></button>
               <h3 className="text-3xl font-black">{authStep === AuthSubView.LOGIN ? 'Welcome' : 'Join Us'}</h3>
            </div>
            <input type="tel" value={phone} autoComplete="tel" onChange={e => setPhone(e.target.value)} placeholder="Mobile Number" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            <input type="password" value={password} autoComplete="current-password" onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            {authStep === AuthSubView.SIGNUP && <input type="password" value={confirmPassword} autoComplete="new-password" onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />}

            {loginError && (
              <div className="bg-rose-50 border border-rose-100 p-4 rounded-xl">
                <p className="text-rose-600 text-[11px] font-black uppercase leading-tight">{loginError}</p>
              </div>
