          {view === AppView.AUTH && renderAuth()}
          {view === AppView.HOME && (
             <div className="space-y-16 animate-fadeIn max-w-6xl mx-auto py-10">
               <div className="text-center space-y-4">
                 <h1 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">TARGET <span className="text-blue-600">SELECTION.</span></h1>
                 <p className="text-slate-500 font-bold text-lg md:text-xl opacity-70">Complete Rajasthan Exam PYQ Database 2015-2026.</p>
               </div>
               <div className="grid md:grid-cols-3 gap-8 px-4">
                 {[
                   { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-blue-600 to-indigo-900", desc: "Original RSSB & RPSC Papers." },
                   { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-emerald-500 to-teal-800", desc: "History, Geo, Culture, Polity." },
                   { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Practice Question Sets." }
                 ].map(card => (
                   <button key={card.title} onClick={card.onClick} className={`p-10 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group active:scale-95`}>
                     <h3 className="text-3xl font-black mb-2 uppercase">{card.title}</h3>
                     <p className="text-white/60 font-bold text-sm mb-8">{card.desc}</p>
                     <div className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">Explore <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
                   </button>
                 ))}
               </div>
             </div>
          )}
          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto py-6 animate-fadeIn">
              {renderBackButton()}
              <div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl text-center">
                <div className="w-24 h-24 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white text-3xl font-black mb-6 uppercase shadow-lg shadow-blue-100">
                   <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 24 24"><path fillRule="evenodd" d="M7.5 6a4.5 4.5 0 119 0 4.5 4.5 0 01-9 0zM3.751 20.105a8.25 8.25 0 0116.498 0 .75.75 0 01-.437.695A18.683 18.683 0 0112 22.5c-2.786 0-5.433-.608-7.812-1.7a.75.75 0 01-.437-.695z" clipRule="evenodd" /></svg>
                </div>
                <h2 className="text-3xl font-black mb-2">{phone}</h2>
                <div className="grid grid-cols-3 gap-4 mt-12">
                  <div className="bg-slate-50 p-6 rounded-2xl">
                      <div className="text-2xl font-black text-blue-600">{Object.keys(userProgress).length}</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Solved</div>
                  </div>
                  <div className="bg-slate-50 p-6 rounded-2xl cursor-pointer hover:bg-rose-50 transition-colors" onClick={() => navigateTo(AppView.BOOKMARKS)}>
                      <div className="text-2xl font-black text-rose-500">{bookmarks.length}</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Bookmarks</div>
                  </div>
                  <div className="bg-slate-50 p-6 rounded-2xl">
                      <div className="text-2xl font-black text-slate-900">10K+</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total</div>
                  </div>
                </div>
              </div>
            </div>
          )}
          {view === AppView.EXAM_MENU && (
             <div className="animate-fadeIn max-w-6xl mx-auto py-6 px-4">
               {renderBackButton()}
               <div className="flex flex-col gap-8 mb-10">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <h2 className="text-4xl font-black uppercase italic">Official Exam Papers</h2>
                    <div className="relative w-full md:w-80">
                      <input 
                        type="text" 
                        value={examSearch}
                        onChange={(e) => setExamSearch(e.target.value)}
                        placeholder="Search exam name..." 
                        className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-3 px-12 font-bold outline-none focus:border-blue-600 transition-all text-sm"
                      />
                      <svg className="w-5 h-5 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    </div>
                  </div>
                  <div className="flex flex-wrap gap-2 pb-4 border-b border-slate-100">
                    {examCategories.map(cat => (
                      <button 
                        key={cat} 
                        onClick={() => toggleCategory(cat)} 
                        className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border-2 ${selectedExamCategories.includes(cat) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'}`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
               </div>

               {filteredExams.length === 0 ? (
                 <div className="text-center py-20 bg-white rounded-[3.5rem] border-2 border-dashed border-slate-200">
                    <p className="text-slate-400 font-bold text-lg italic">No papers match your search/filter.</p>
                 </div>
               ) : (
                 <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                   {filteredExams.map((exam, i) => {
                     const testId = `exam_${exam.name}_${exam.year}`;
                     const score = userProgress[testId];
                     const isDone = score !== undefined;
                     return (
                       <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: exam.count })} className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all text-left group relative overflow-hidden ${isDone ? 'border-emerald-100' : 'border-slate-50 hover:border-blue-600 shadow-sm hover:shadow-xl'}`}>
                         {isDone && <div className="absolute top-4 right-4 bg-emerald-500 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg></div>}
                         <div className="flex justify-between mb-4">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{exam.category} • {exam.year}</span>
                         </div>
                         <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-6">{exam.name}</h3>
                         <div className="flex items-center justify-between">
                            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1 rounded-full">{exam.count} Questions</div>
                            {isDone && <div className="text-xs font-black text-emerald-600">Score: {score.toFixed(1)}%</div>}
                         </div>
                       </button>
                     );
                   })}
                 </div>
               )}
             </div>
          )}
          {view === AppView.QUIZ_TOPIC_MENU && (
             <div className="animate-fadeIn max-w-4xl mx-auto py-6 px-4">
                {renderBackButton()}
                <h2 className="text-4xl font-black uppercase italic mb-10">Topics Wise Tests</h2>
                <div className="grid gap-4">
                  {TOPIC_GROUPS.map(g => (
                    <button key={g.id} onClick={() => { setSelectedGroup(g); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="p-10 bg-white border-2 border-slate-50 rounded-[2.5rem] text-left hover:border-emerald-600 transition-all flex items-center justify-between group active:scale-95 shadow-sm hover:shadow-lg">
                      <div>
                        <h3 className="text-2xl font-black uppercase group-hover:text-emerald-600 transition-colors">{g.name}</h3>
                        <p className="text-slate-400 font-bold text-xs uppercase mt-1">{g.subtopics.length} Categories</p>
                      </div>
                      <svg className="w-6 h-6 text-slate-200 group-hover:text-emerald-600 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                    </button>
                  ))}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_SUBTOPIC_MENU && (
             <div className="animate-fadeIn max-w-3xl mx-auto py-6 px-4">
                {renderBackButton(AppView.QUIZ_TOPIC_MENU)}
                <div className="flex items-center gap-4 mb-10 border-l-8 border-emerald-500 pl-6 py-2">
                  <h2 className="text-2xl font-black italic">{selectedGroup?.name}</h2>
                </div>
                <div className="grid gap-3">
                  {selectedGroup?.subtopics.map(s => {
                    const testId = `topic_${s}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;
                    return (
                      <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { testId, topic: s })} className={`p-6 bg-white border-2 transition-all hindi-text font-bold text-lg rounded-2xl text-left flex items-center justify-between group active:scale-95 shadow-sm hover:shadow-md ${isDone ? 'border-emerald-100 bg-emerald-50/20' : 'border-slate-50 hover:bg-emerald-50 hover:border-emerald-600'}`}>
                        <div className="flex flex-col">
                           <span>{s}</span>
                           {isDone && <span className="text-xs font-black text-emerald-600 mt-1 uppercase tracking-widest font-sans">Score: {score.toFixed(1)}%</span>}
                        </div>
                        {isDone && <div className="bg-emerald-500 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg></div>}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_MIX_MENU && (
             <div className="animate-fadeIn max-w-6xl mx-auto py-6 px-4">
                {renderBackButton()}
                <h2 className="text-4xl font-black uppercase italic mb-10">Mixed Mocks (1-200)</h2>
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 h-[600px] overflow-y-auto custom-scrollbar">
                  {Array.from({ length: 200 }).map((_, i) => {
                    const testId = `mix_set_${i+1}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;
                    return (
                      <button key={i} onClick={() => startQuiz(QuizType.MIX, `Set #${i+1}`, { testId, testNumber: i+1 })} className={`p-4 rounded-xl border transition-all font-bold flex flex-col items-center justify-center relative active:scale-90 ${isDone ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-white border-slate-100 hover:bg-slate-900 hover:text-white'}`}>
                        <span>Set #{i+1}</span>
                        {isDone && <div className="text-[10px] font-black mt-1">{score.toFixed(0)}%</div>}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}
          {view === AppView.QUIZ_ACTIVE && activeSession && (
             <QuizEngine 
                session={activeSession} 
                onComplete={onQuizComplete} 
                onExit={() => navigateTo(AppView.HOME)} 
                onToggleBookmark={toggleBookmark}
                bookmarkedIds={bookmarks.map(b => b.id)}
             />
          )}
          {view === AppView.SCORECARD && lastResults && <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />}
          {view === AppView.REVIEW && lastResults && (
             <QuizEngine 
                session={lastResults.session} 
                onComplete={() => {}} 
                onExit={() => navigateTo(AppView.SCORECARD)} 
                isReview={true} 
                onToggleBookmark={toggleBookmark}
                bookmarkedIds={bookmarks.map(b => b.id)}
             />
          )}
          {view === AppView.BOOKMARKS && renderBookmarks()}
        </>
      )}
    </Layout>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.tsx';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);

  // Enhanced Filtering State
  const [examSearch, setExamSearch] = useState('');
  const [selectedExamCategories, setSelectedExamCategories] = useState<string[]>(['All']);

  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('rajquiz_currentUser');
    if (savedUser) {
      loginUser(savedUser);
    }
  }, []);

  const loginUser = (userPhone: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setView(AppView.HOME);

    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testKey: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testKey]: Math.max(userProgress[testKey] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];

    if (!user) { 
      setLoginError("This number is not registered. Sign up first."); 
      setAuthStep(AuthSubView.SIGNUP);
      return; 
    }

    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone);
      setLoginError('');
    } else { 
      setLoginError("Invalid password."); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) {
      setLoginError("Enter a valid mobile number.");
      return;
    }
    if (password !== confirmPassword) {
      setLoginError("Passwords do not match.");
      return;
    }

    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    users[phone] = { password };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));

    localStorage.setItem('rajquiz_currentUser', phone);
    loginUser(phone);
    setLoginError('');
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 60, completed: false,
        testId: options.testId
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("Error fetching questions. Please try again.");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });

    const totalQuestions = session.questions.length;
    const maxScore = totalQuestions * 2;
    const percentage = Math.max(0, (score / maxScore) * 100);

    if (session.testId) {
      saveProgress(session.testId, percentage);
    }

    setLastResults({ 
      score, correctCount: correct, incorrectCount: incorrect, 
      skippedCount: skipped, unattemptedCount: unattempted, 
      totalQuestions, session 
    } as any);
    navigateTo(AppView.SCORECARD);
  };

  const filteredExams = useMemo(() => {
    return OFFICIAL_EXAMS.filter(exam => {
      const matchesSearch = exam.name.toLowerCase().includes(examSearch.toLowerCase()) || 
                            exam.category.toLowerCase().includes(examSearch.toLowerCase());
      const matchesCategory = selectedExamCategories.includes('All') || 
                              selectedExamCategories.includes(exam.category);
      return matchesSearch && matchesCategory;
    });
  }, [examSearch, selectedExamCategories]);

  const examCategories = useMemo(() => {
    const cats = new Set(OFFICIAL_EXAMS.map(e => e.category));
    return ['All', ...Array.from(cats)];
  }, []);

  const toggleExamCategory = (cat: string) => {
    if (cat === 'All') {
      setSelectedExamCategories(['All']);
      return;
    }

    let next = selectedExamCategories.filter(c => c !== 'All');
    if (next.includes(cat)) {
      next = next.filter(c => c !== cat);
      if (next.length === 0) next = ['All'];
    } else {
      next = [...next, cat];
    }
    setSelectedExamCategories(next);
  };

  const renderBackButton = (target: AppView = AppView.HOME) => (
    <button 
      onClick={() => navigateTo(target)}
      className="mb-8 flex items-center gap-2 text-slate-400 font-black hover:text-blue-600 transition-colors uppercase tracking-widest text-xs group"
    >
      <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
      </svg>
      Back
    </button>
  );

  const renderAuth = () => (
    <div className="min-h-[70vh] flex items-center justify-center">
      <div className="bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-100">
        {authStep === AuthSubView.CHOICE ? (
          <div className="text-center space-y-10">
            <h2 className="text-4xl font-black text-blue-600 italic tracking-tighter">RAJQUIZER.</h2>
            <div className="space-y-4">
              <button onClick={() => setAuthStep(AuthSubView.LOGIN)} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all">LOGIN</button>
              <button onClick={() => setAuthStep(AuthSubView.SIGNUP)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all">SIGN UP</button>
            </div>
          </div>
        ) : (
          <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-4">
            <div className="flex items-center gap-2 mb-2">
               <button type="button" onClick={() => setAuthStep(AuthSubView.CHOICE)} className="text-slate-400 hover:text-blue-600"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7"/></svg></button>
               <h3 className="text-3xl font-black">{authStep === AuthSubView.LOGIN ? 'Welcome' : 'Join Us'}</h3>
            </div>
            <input type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="Mobile Number" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />
            {authStep === AuthSubView.SIGNUP && <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-blue-600 outline-none font-bold" required />}

            {loginError && (
              <div className="bg-rose-50 border border-rose-100 p-4 rounded-xl">
                <p className="text-rose-600 text-[11px] font-black uppercase leading-tight">{loginError}</p>
              </div>
            )}

            <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 mt-4 transition-transform active:scale-95">Continue</button>
            <button type="button" onClick={() => { setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN); setLoginError(''); }} className="w-full py-2 text-blue-600 font-bold text-xs uppercase tracking-widest mt-2">
              {authStep === AuthSubView.LOGIN ? 'Create Account' : 'Back to Login'}
            </button>
          </form>
        )}
      </div>
    </div>
  );

  const handleLogout = () => {
    localStorage.removeItem('rajquiz_currentUser');
    setIsLoggedIn(false);
    setUserProgress({});
    setBookmarks([]);
    navigateTo(AppView.AUTH);
  };

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onTopicTestsClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)}
      onExamPapersClick={() => navigateTo(AppView.EXAM_MENU)}
      onBookmarksClick={() => navigateTo(AppView.BOOKMARKS)}
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout}
      isLoggedIn={isLoggedIn}
    >
      {loading ? (
        <div className="min-h-[60vh] flex flex-col items-center justify-center animate-fadeIn">
          <div className="relative w-24 h-24 mb-6">
            <div className="absolute inset-0 border-[6px] border-slate-100 rounded-full"></div>
            <div className="absolute inset-0 border-[6px] border-blue-600 rounded-full border-t-transparent animate-spin"></div>
          </div>
          <h2 className="text-2xl font-black uppercase tracking-[0.2em] text-slate-300">Fetching PYQs...</h2>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && renderAuth()}

          {view === AppView.HOME && (
             <div className="space-y-16 animate-fadeIn max-w-6xl mx-auto py-10">
               <div className="text-center space-y-4">
                 <h1 className="text-6xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">TARGET <span className="text-blue-600">SELECTION.</span></h1>
                 <p className="text-slate-500 font-bold text-lg md:text-xl opacity-70">Official RSSB & RPSC PYQ Database 2015-2026.</p>
               </div>
               <div className="grid md:grid-cols-3 gap-8 px-4">
                 {[
                   { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-blue-600 to-indigo-900", desc: "Original Full Papers." },
                   { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-emerald-500 to-teal-800", desc: "History, Geo, Dynasties." },
                   { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Practice Sets." }
                 ].map(card => (
                   <button key={card.title} onClick={card.onClick} className={`p-12 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white transition-all shadow-xl hover:shadow-2xl hover:-translate-y-2 group active:scale-95`}>
                     <h3 className="text-3xl font-black mb-2 uppercase">{card.title}</h3>
                     <p className="text-white/60 font-bold text-sm mb-8">{card.desc}</p>
                     <div className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">Explore <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
                   </button>
                 ))}
               </div>
             </div>
          )}

          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto py-6 animate-fadeIn">
              {renderBackButton()}
              <div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl text-center">
                <div className="w-24 h-24 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white text-3xl font-black mb-6 shadow-lg shadow-blue-100">
                   <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 24 24"><path fillRule="evenodd" d="M7.5 6a4.5 4.5 0 119 0 4.5 4.5 0 01-9 0zM3.751 20.105a8.25 8.25 0 0116.498 0 .75.75 0 01-.437.695A18.683 18.683 0 0112 22.5c-2.786 0-5.433-.608-7.812-1.7a.75.75 0 01-.437-.695z" clipRule="evenodd" /></svg>
                </div>
                <h2 className="text-3xl font-black mb-2">{phone}</h2>
                <div className="grid grid-cols-3 gap-4 mt-12">
                  <div className="bg-slate-50 p-6 rounded-2xl">
                      <div className="text-2xl font-black text-blue-600">{Object.keys(userProgress).length}</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Solved</div>
                  </div>
                  <div className="bg-slate-50 p-6 rounded-2xl cursor-pointer hover:bg-rose-50 transition-colors" onClick={() => navigateTo(AppView.BOOKMARKS)}>
                      <div className="text-2xl font-black text-rose-500">{bookmarks.length}</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Saved</div>
                  </div>
                  <div className="bg-slate-50 p-6 rounded-2xl">
                      <div className="text-2xl font-black">10K+</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Available</div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {view === AppView.EXAM_MENU && (
             <div className="animate-fadeIn max-w-6xl mx-auto py-6 px-4">
               {renderBackButton()}
               <div className="flex flex-col gap-8 mb-10">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <h2 className="text-4xl font-black uppercase italic">Official Papers</h2>
                    <div className="relative w-full md:w-96">
                      <input 
                        type="text" 
                        value={examSearch}
                        onChange={(e) => setExamSearch(e.target.value)}
                        placeholder="Search exam name..." 
                        className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-12 font-bold outline-none focus:border-blue-600 transition-all text-sm"
                      />
                      <svg className="w-5 h-5 text-slate-400 absolute left-4 top-1/2 -translate-y-1/2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    </div>
                  </div>
                  <div className="flex flex-wrap gap-2 pb-6 border-b border-slate-100">
                    {examCategories.map(cat => (
                      <button 
                        key={cat} 
                        onClick={() => toggleExamCategory(cat)} 
                        className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border-2 ${selectedExamCategories.includes(cat) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200'}`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
               </div>

               {filteredExams.length === 0 ? (
                 <div className="text-center py-20 bg-white rounded-[3.5rem] border-2 border-dashed border-slate-200">
                    <p className="text-slate-400 font-bold text-lg italic">No papers match your selection.</p>
                 </div>
               ) : (
                 <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                   {filteredExams.map((exam, i) => {
                     const testId = `exam_${exam.name}_${exam.year}`;
                     const score = userProgress[testId];
                     const isDone = score !== undefined;
                     return (
                       <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { testId, examContext: exam.context, count: exam.count })} className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all text-left group relative overflow-hidden ${isDone ? 'border-emerald-100 bg-emerald-50/10' : 'border-slate-50 hover:border-blue-600 shadow-sm hover:shadow-xl'}`}>
                         {isDone && <div className="absolute top-4 right-4 bg-emerald-500 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg></div>}
                         <div className="flex justify-between mb-4">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{exam.category} • {exam.year}</span>
                         </div>
                         <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-6">{exam.name}</h3>
                         <div className="flex items-center justify-between">
                            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1 rounded-full">{exam.count} Questions</div>
                            {isDone && <div className="text-xs font-black text-emerald-600">Best: {score.toFixed(1)}%</div>}
                         </div>
                       </button>
                     );
                   })}
                 </div>
               )}
             </div>
          )}

          {view === AppView.QUIZ_TOPIC_MENU && (
             <div className="animate-fadeIn max-w-4xl mx-auto py-6 px-4">
                {renderBackButton()}
                <h2 className="text-4xl font-black uppercase italic mb-10">Topics Wise</h2>
                <div className="grid gap-4">
                  {TOPIC_GROUPS.map(g => (
                    <button key={g.id} onClick={() => { setSelectedGroup(g); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="p-10 bg-white border-2 border-slate-50 rounded-[2.5rem] text-left hover:border-emerald-600 transition-all flex items-center justify-between group active:scale-95 shadow-sm">
                      <div>
                        <h3 className="text-2xl font-black uppercase group-hover:text-emerald-600 transition-colors">{g.name}</h3>
                        <p className="text-slate-400 font-bold text-xs uppercase mt-1">{g.subtopics.length} Sections</p>
                      </div>
                      <svg className="w-6 h-6 text-slate-200 group-hover:text-emerald-600 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                    </button>
                  ))}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_SUBTOPIC_MENU && (
             <div className="animate-fadeIn max-w-3xl mx-auto py-6 px-4">
                {renderBackButton(AppView.QUIZ_TOPIC_MENU)}
                <div className="flex items-center gap-4 mb-10 border-l-8 border-emerald-500 pl-6 py-2">
                  <h2 className="text-2xl font-black italic uppercase">{selectedGroup?.name}</h2>
                </div>
                <div className="grid gap-3">
                  {selectedGroup?.subtopics.map(s => {
                    const testId = `topic_${s}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;
                    return (
                      <button key={s} onClick={() => startQuiz(QuizType.TOPIC, s, { testId, topic: s })} className={`p-6 bg-white border-2 transition-all hindi-text font-bold text-lg rounded-2xl text-left flex items-center justify-between group active:scale-95 shadow-sm hover:shadow-md ${isDone ? 'border-emerald-100 bg-emerald-50/20' : 'border-slate-50 hover:bg-emerald-50 hover:border-emerald-600'}`}>
                        <div className="flex flex-col">
                           <span className="leading-relaxed">{s}</span>
                           {isDone && <span className="text-xs font-black text-emerald-600 mt-2 uppercase tracking-widest font-sans">Score: {score.toFixed(1)}%</span>}
                        </div>
                        {isDone && <div className="bg-emerald-500 text-white p-1 rounded-full"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg></div>}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_MIX_MENU && (
             <div className="animate-fadeIn max-w-6xl mx-auto py-6 px-4">
                {renderBackButton()}
                <h2 className="text-4xl font-black uppercase italic mb-10">Mixed Sets (1-200)</h2>
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 h-[600px] overflow-y-auto custom-scrollbar pr-4">
                  {Array.from({ length: 200 }).map((_, i) => {
                    const testId = `mix_set_${i+1}`;
                    const score = userProgress[testId];
                    const isDone = score !== undefined;
                    return (
                      <button key={i} onClick={() => startQuiz(QuizType.MIX, `Set #${i+1}`, { testId, testNumber: i+1 })} className={`p-5 rounded-2xl border transition-all font-bold flex flex-col items-center justify-center relative active:scale-90 ${isDone ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-white border-slate-100 hover:bg-slate-900 hover:text-white shadow-sm'}`}>
                        <span className="text-sm">Set #{i+1}</span>
                        {isDone && <div className="text-[10px] font-black mt-1 uppercase tracking-tighter">{score.toFixed(0)}%</div>}
                      </button>
                    );
                  })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
             <QuizEngine 
                session={activeSession} 
                onComplete={onQuizComplete} 
                onExit={() => navigateTo(AppView.HOME)} 
                onToggleBookmark={toggleBookmark}
                bookmarkedIds={bookmarks.map(b => b.id)}
             />
          )}

          {view === AppView.SCORECARD && lastResults && <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />}

          {view === AppView.REVIEW && lastResults && (
             <QuizEngine 
                session={lastResults.session} 
                onComplete={() => {}} 
                onExit={() => navigateTo(AppView.SCORECARD)} 
                isReview={true} 
                onToggleBookmark={toggleBookmark}
                bookmarkedIds={bookmarks.map(b => b.id)}
             />
          )}

          {view === AppView.BOOKMARKS && (
            <div className="max-w-4xl mx-auto py-6 animate-fadeIn">
              {renderBackButton()}
              <div className="flex items-center justify-between mb-10 px-4">
                <h2 className="text-4xl font-black uppercase italic">Saved PYQs</h2>
                <span className="bg-blue-600 text-white px-5 py-2 rounded-full text-xs font-black shadow-lg shadow-blue-100">{bookmarks.length} Total</span>
              </div>
              {bookmarks.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[3.5rem] border-2 border-dashed border-slate-200">
                   <p className="text-slate-400 font-bold text-lg mb-4">No saved questions.</p>
                   <button onClick={() => navigateTo(AppView.HOME)} className="text-blue-600 font-black uppercase text-xs tracking-widest">Start Preparing →</button>
                </div>
              ) : (
                <div className="space-y-6 px-4">
                  {bookmarks.map((q) => (
                    <div key={q.id} className="bg-white p-10 rounded-[2.5rem] shadow-xl border border-slate-100 relative group">
                       <button onClick={() => toggleBookmark(q)} className="absolute top-8 right-8 text-rose-500 hover:scale-125 transition-transform"><svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24"><path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/></svg></button>
                       <div className="flex gap-3 mb-6">
                          <span className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full">{q.examName}</span>
                          <span className="text-[10px] font-black uppercase text-slate-400 bg-slate-50 px-3 py-1.5 rounded-full">{q.examYear}</span>
                       </div>
                       <p className="text-2xl font-bold hindi-text leading-relaxed mb-8">{q.question}</p>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                         {['A','B','C','D'].map(key => (
                           <div key={key} className={`p-4 rounded-2xl border-2 ${key === q.correctAnswer ? 'bg-emerald-50 border-emerald-200' : 'bg-slate-50 border-slate-100 opacity-60'}`}>
                             <span className="font-black mr-3 text-slate-400">{key}</span>
                             <span className="hindi-text font-bold">{(q.options as any)[key]}</span>
                           </div>
                         ))}
                       </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  QUIZ_TOPIC_TESTS_MENU = 'quiz_topic_tests_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review',
  PROFILE = 'profile',
  EDIT_PROFILE = 'edit_profile',
  BOOKMARKS = 'bookmarks'
}

export enum AuthSubView {
  CHOICE = 'choice',
  LOGIN = 'login',
  SIGNUP = 'signup',
  FORGOT_PHONE = 'forgot_phone',
  FORGOT_OTP = 'forgot_otp',
  RESET_PASSWORD = 'reset_password'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface User {
  phone: string;
  name?: string;
  password?: string;
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
  testId?: string;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

export interface AttemptRecord {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  date: number;
  correct: number;
  total: number;
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question,
  User
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // User Profile State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [editName, setEditName] = useState('');

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);

  // Enhanced Filtering State
  const [examSearch, setExamSearch] = useState('');
  const [selectedExamCategories, setSelectedExamCategories] = useState<string[]>(['All']);

  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUserPhone = localStorage.getItem('rajquiz_currentUser');
    if (savedUserPhone) {
      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      const userData = users[savedUserPhone];
      if (userData) {
        loginUser(savedUserPhone, userData.name);
      }
    }
  }, []);

  const loginUser = (userPhone: string, userName?: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setCurrentUser({ phone: userPhone, name: userName });
    setEditName(userName || '');
    setView(AppView.HOME);

    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testKey: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testKey]: Math.max(userProgress[testKey] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];

    if (!user) { 
      setLoginError("Number is not registered. Sign up first."); 
      setAuthStep(AuthSubView.SIGNUP);
      return; 
    }

    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone, user.name);
      setLoginError('');
    } else { 
      setLoginError("Invalid password."); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) {
      setLoginError("Enter a valid mobile number.");
      return;
    }
    if (password !== confirmPassword) {
      setLoginError("Passwords do not match.");
      return;
    }

    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    users[phone] = { password, name: '' };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));

    localStorage.setItem('rajquiz_currentUser', phone);
    loginUser(phone, '');
    setLoginError('');
  };

  const handleUpdateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    if (!phone) return;

    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) {
      users[phone].name = editName;
      localStorage.setItem('rajquiz_users', JSON.stringify(users));
      setCurrentUser(prev => prev ? { ...prev, name: editName } : { phone, name: editName });
      alert("Profile updated successfully!");
      navigateTo(AppView.PROFILE);
    }
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 60, completed: false,
        testId: options.testId
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("Error fetching questions. Please try again.");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });

    const totalQuestions = session.questions.length;
    const maxScore = totalQuestions * 2;
    const percentage = Math.max(0, (score / maxScore) * 100);

    if (session.testId) {
      saveProgress(session.testId, percentage);
    }

    setLastResults({ 
      score, correctCount: correct, incorrectCount: incorrect, 
      skippedCount: skipped, unattemptedCount: unattempted, 
      totalQuestions, session 
    } as any);
    navigateTo(AppView.SCORECARD);
  };

  const filteredExams = useMemo(() => {
    return OFFICIAL_EXAMS.filter(exam => {
      const matchesSearch = exam.name.toLowerCase().includes(examSearch.toLowerCase()) || 
                            exam.category.toLowerCase().includes(examSearch.toLowerCase());
      const matchesCategory = selectedExamCategories.includes('All') || 
                              selectedExamCategories.includes(exam.category);
      return matchesSearch && matchesCategory;
    });
  }, [examSearch, selectedExamCategories]);

  const examCategories = useMemo(() => {
    const cats = new Set(OFFICIAL_EXAMS.map(e => e.category));
    return ['All', ...Array.from(cats)];
  }, []);

  const toggleExamCategory = (cat: string) => {
    if (cat === 'All') {
      setSelectedExamCategories(['All']);
      return;
    }

    let next = selectedExamCategories.filter(c => c !== 'All');
    if (next.includes(cat)) {
      next = next.filter(c => c !== cat);
      if (next.length === 0) next = ['All'];
    } else {
      next = [...next, cat];
    }
    setSelectedExamCategories(next);
  };

