                       <svg className="w-10 h-10 text-slate-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg>
                    </div>
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">No saved questions yet.</p>
                 </div>
               ) : (
                 <div className="grid gap-6">
                    {bookmarks.map((q, i) => (
                      <div key={q.id} className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
                         <div className="flex items-center justify-between mb-6">
