                <div className="w-32 h-32 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white text-3xl font-black mb-6 shadow-lg shadow-blue-100 overflow-hidden border-4 border-white">
                   {currentUser?.profilePic ? (
                     <img src={currentUser.profilePic} alt="Profile" className="w-full h-full object-cover" />
                   ) : (
                     <svg className="w-16 h-16" fill="currentColor" viewBox="0 0 24 24"><path fillRule="evenodd" d="M7.5 6a4.5 4.5 0 119 0 4.5 4.5 0 01-9 0zM3.751 20.105a8.25 8.25 0 0116.498 0 .75.75 0 01-.437.695A18.683 18.683 0 0112 22.5c-2.786 0-5.433-.608-7.812-1.7a.75.75 0 01-.437-.695z" clipRule="evenodd" /></svg>
                   )}
                </div>
                <h3 className="text-3xl font-black text-slate-900 mb-1">{currentUser?.name || 'RAJQUIZER Aspirant'}</h3>
                <p className="text-slate-400 font-bold mb-8">{phone}</p>

                <div className="grid grid-cols-2 gap-4 mb-10">
                   <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <span className="text-2xl font-black text-slate-800">{Object.keys(userProgress).length}</span>
                      <span className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Tests Done</span>
                   </div>
                   <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <span className="text-2xl font-black text-slate-800">{bookmarks.length}</span>
                      <span className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Saved Qs</span>
                   </div>
                </div>

                <div className="space-y-3">
                   <button onClick={() => navigateTo(AppView.EDIT_PROFILE)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl hover:bg-slate-800 transition-all">Edit Profile</button>
                   <button onClick={handleLogout} className="w-full py-4 bg-white text-rose-600 border-2 border-rose-50 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-rose-50 transition-all">Logout</button>
                </div>
              </div>
            </div>
          )}

          {view === AppView.EDIT_PROFILE && (
            <div className="max-w-2xl mx-auto py-6 animate-fadeIn">
              {renderBackButton(AppView.PROFILE)}
              <div className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-xl">
                 <h3 className="text-3xl font-black mb-10 text-center">Update <span className="text-blue-600">Profile</span></h3>
                 <form onSubmit={handleUpdateProfile} className="space-y-6">
                    <div className="flex flex-col items-center mb-10">
                       <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                          <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center text-slate-300 overflow-hidden border-2 border-slate-200 group-hover:border-blue-500 transition-all">
                             {editProfilePic ? (
                               <img src={editProfilePic} alt="Preview" className="w-full h-full object-cover" />
                             ) : (
                               <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 24 24"><path d="M12 9a3 3 0 100 6 3 3 0 000-6z" /><path fillRule="evenodd" d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zM4 12a8 8 0 1116 0 8 8 0 01-16 0z" clipRule="evenodd" /></svg>
                             )}
                          </div>
                          <div className="absolute inset-0 bg-black/40 rounded-full opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                             <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
                          </div>
                          <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
