import { GoogleGenAI, Type } from "@google/genai";
import { Question } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fetchPYQs(params: {
  count: number;
  subject?: string;
  topic?: string;
  isMix?: boolean;
  testNumber?: number;
  examContext?: string;
}): Promise<Question[]> {
  const { count, subject, topic, isMix, testNumber, examContext } = params;

  // Use testNumber to ensure uniqueness across 200 sets
  const seedDescriptor = isMix 
    ? `MIXED GK SET #${testNumber} (PART ${Math.ceil((testNumber || 1) / 10)} OF ARCHIVE)` 
    : (topic || subject || 'Rajasthan GK');

  const prompt = `ACT AS THE OFFICIAL RPSC & RSSB EXAM DATABASE ARCHIVIST.

  TASK: RETRIEVE ${count} AUTHENTIC PREVIOUS YEAR QUESTIONS (PYQs).

  CONTEXT: 
  - TARGET: ${seedDescriptor}
  - SCOPE: Rajasthan History, Geography, Polity, Economy, and Culture.
  - TEST INDEX: ${testNumber || 1} (USE THIS INDEX TO ENSURE QUESTIONS ARE UNIQUE AND DIFFERENT FROM PREVIOUS SETS).

  STRICT REPETITION PROTOCOL: 
  THE USER IS GENERATING 200 DIFFERENT SETS. THIS IS SET #${testNumber}. 
  DO NOT PROVIDE QUESTIONS THAT ARE COMMONLY FOUND IN SETS 1-10 IF THIS IS SET 50. 
  ROTATE THROUGH THE ENTIRE 10,000+ QUESTION BANK OF RAJASTHAN EXAMS.

  REQUIREMENTS:
  1. LANGUAGE: HINDI ONLY.
  2. FORMAT: MUST BE REAL EXAM QUESTIONS FROM RPSC/RSSB.
  3. OPTIONS: PROVIDE A, B, C, D AND OPTION E AS "अनुत्तरित प्रश्न".
  4. VALIDATION: ENSURE THE CORRECT ANSWER IS ACCURATE ACCORDING TO OFFICIAL KEY.

  RESPONSE FORMAT: 
  RETURN ONLY A JSON ARRAY OF OBJECTS. NO PREAMBLE. NO MARKDOWN WRAPPERS.

  JSON SCHEMA:
  [{
    "id": "pyq_set_${testNumber || 0}_${Date.now()}_[index]",
    "question": "Hindi text",
    "options": {"A":"..","B":"..","C":"..","D":"..","E":"अनुत्तरित प्रश्न"},
    "correctAnswer": "A",
    "examName": "Actual Exam Name (e.g. RAS Pre, Patwari, CET)",
    "examYear": 2022,
    "subject": "Category"
  }]`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        temperature: 1, // Higher temperature to avoid repetition
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: {
                type: Type.OBJECT,
                properties: {
                  A: { type: Type.STRING },
                  B: { type: Type.STRING },
                  C: { type: Type.STRING },
                  D: { type: Type.STRING },
                  E: { type: Type.STRING },
                },
                required: ['A', 'B', 'C', 'D', 'E']
              },
              correctAnswer: { type: Type.STRING, enum: ['A', 'B', 'C', 'D', 'E'] },
              examName: { type: Type.STRING },
              examYear: { type: Type.NUMBER },
              subject: { type: Type.STRING },
            },
            required: ['id', 'question', 'options', 'correctAnswer', 'examName', 'examYear', 'subject']
          }
        }
      }
    });

    let jsonStr = response.text.trim();
    // Sometimes the model wraps in markdown
    if (jsonStr.startsWith('```json')) {
      jsonStr = jsonStr.replace(/^```json/, '').replace(/```$/, '').trim();
    }

    const parsed = JSON.parse(jsonStr);
    return parsed.slice(0, count);
  } catch (error) {
    console.error("Gemini PYQ Fetch Error:", error);
    throw error;
  }
}

