                              <p className="text-slate-400 font-bold text-sm">{exam.count} Questions</p>
                           </div>
                           <div className="flex items-center justify-between pt-8">
                              <div className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-2">Start Paper <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6"/></svg></div>
                              {progress > 0 && <div className="text-[10px] font-black text-emerald-600">{Math.round(progress)}% Score</div>}
                           </div>
                        </button>
                      );
                   })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} onToggleBookmark={toggleBookmark} bookmarkedIds={bookmarks.map(b => b.id)} />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine session={lastResults.session} onComplete={() => navigateTo(AppView.HOME)} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} onToggleBookmark={toggleBookmark} bookmarkedIds={bookmarks.map(b => b.id)} />
          )}

          {view === AppView.BOOKMARKS && (
            <div className="max-w-4xl mx-auto px-4">
               {renderBackButton()}
               <h2 className="text-4xl font-black mb-10 uppercase tracking-tighter">Saved <span className="text-rose-600">Questions</span></h2>
               {bookmarks.length === 0 ? (
                 <div className="bg-white p-20 rounded-[3rem] text-center border-2 border-dashed border-slate-100 text-slate-300 font-black uppercase">No Bookmarks Saved</div>
               ) : (
                 <div className="grid gap-6">
                    {bookmarks.map(q => (
                      <div key={q.id} className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm relative animate-fadeIn">
                         <button onClick={() => toggleBookmark(q)} className="absolute top-8 right-8 text-rose-600 font-black text-xs uppercase hover:underline">Remove</button>
                         <h3 className="text-xl font-bold mb-6 hindi-text pr-16 text-slate-800">{q.question}</h3>
                         <div className="grid gap-2">
                            {['A','B','C','D'].map(key => (
                               <div key={key} className={`p-4 rounded-xl border-2 flex items-center gap-4 ${q.correctAnswer === key ? 'bg-emerald-50 border-emerald-500' : 'border-slate-50'}`}>
                                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black ${q.correctAnswer === key ? 'bg-emerald-600 text-white' : 'bg-slate-50 text-slate-300'}`}>{key}</div>
                                  <span className="hindi-text font-bold text-slate-700">{q.options[key as 'A'|'B'|'C'|'D']}</span>
                               </div>
                            ))}
                         </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto animate-fadeIn px-4">
              {renderBackButton()}
              <div className="bg-white p-12 rounded-[3.5rem] shadow-xl text-center border border-slate-100">
                <div className="w-32 h-32 bg-blue-600 rounded-full mx-auto mb-6 flex items-center justify-center text-white overflow-hidden border-4 border-white shadow-lg relative group">
                   {currentUser?.profilePic ? <img src={currentUser.profilePic} className="w-full h-full object-cover" /> : <svg className="w-16 h-16" fill="currentColor" viewBox="0 0 24 24"><path d="M7.5 6a4.5 4.5 0 119 0 4.5 4.5 0 01-9 0zM3.751 20.105a8.25 8.25 0 0116.498 0 .75.75 0 01-.437.695A18.683 18.683 0 0112 22.5c-2.786 0-5.433-.608-7.812-1.7a.75.75 0 01-.437-.695z" /></svg>}
                </div>
                <h3 className="text-3xl font-black mb-1 text-slate-900">{currentUser?.name || 'Aspirant'}</h3>
                <p className="text-slate-400 font-bold mb-8">{phone}</p>
                <div className="grid grid-cols-2 gap-4 mb-8">
                   <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <span className="text-2xl font-black text-slate-800">{Object.keys(userProgress).length}</span>
                      <span className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Tests Done</span>
                   </div>
                   <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <span className="text-2xl font-black text-slate-800">{bookmarks.length}</span>
                      <span className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Bookmarks</span>
                   </div>
                </div>
                <div className="space-y-3">
                   <button onClick={() => navigateTo(AppView.EDIT_PROFILE)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg active:scale-95">Edit Profile</button>
                   <button onClick={handleLogout} className="w-full py-4 text-rose-600 font-black text-sm uppercase tracking-widest hover:bg-rose-50 rounded-2xl transition-colors">Logout</button>
                </div>
              </div>
            </div>
          )}

          {view === AppView.EDIT_PROFILE && (
            <div className="max-w-2xl mx-auto animate-fadeIn px-4">
              {renderBackButton(AppView.PROFILE)}
              <div className="bg-white p-12 rounded-[3.5rem] shadow-xl border border-slate-100">
                 <h3 className="text-3xl font-black mb-10 text-center">Update <span className="text-blue-600">Profile</span></h3>
                 <form onSubmit={handleUpdateProfile} className="space-y-6">
                    <div className="flex flex-col items-center mb-10">
                       <div className="relative cursor-pointer group" onClick={() => fileInputRef.current?.click()}>
                          <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center overflow-hidden border-2 border-slate-200 group-hover:border-blue-500 transition-all">
                             {editProfilePic ? <img src={editProfilePic} className="w-full h-full object-cover" /> : <svg className="w-10 h-10 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M12 9a3 3 0 100 6 3 3 0 000-6z" /><path fillRule="evenodd" d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zM4 12a8 8 0 1116 0 8 8 0 01-16 0z" /></svg>}
                          </div>
                          <div className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                             <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
                          </div>
                          <input ref={fileInputRef} type="file" className="hidden" onChange={handleFileChange} />
                       </div>
                       <p className="mt-4 text-[10px] font-black uppercase text-slate-400 tracking-widest">Click to change picture</p>
                    </div>
                    <input type="text" value={editName} onChange={e => setEditName(e.target.value)} placeholder="Full Name" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" />
                    <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 active:scale-95 transition-transform">SAVE PROFILE</button>
                 </form>
              </div>
            </div>
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question,
  User
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [editName, setEditName] = useState('');
  const [editProfilePic, setEditProfilePic] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);

  const [examSearch, setExamSearch] = useState('');
  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUserPhone = localStorage.getItem('rajquiz_currentUser');
    if (savedUserPhone) {
      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      const userData = users[savedUserPhone];
      if (userData) {
        loginUser(savedUserPhone, userData.name, userData.profilePic);
      } else {
        setView(AppView.AUTH);
      }
    } else {
      setView(AppView.AUTH);
    }
  }, []);

  const loginUser = (userPhone: string, userName?: string, profilePic?: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setCurrentUser({ phone: userPhone, name: userName, profilePic });
    setEditName(userName || '');
    setEditProfilePic(profilePic || null);
    setView(AppView.HOME);

    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testId: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testId]: Math.max(userProgress[testId] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { 
      setLoginError("Number is not registered. Sign up first."); 
      return; 
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone, user.name, user.profilePic);
      setLoginError('');
    } else { 
      setLoginError("Invalid password. Please try again."); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) {
      setLoginError("Enter a valid 10-digit mobile number.");
      return;
    }
    if (password !== confirmPassword) {
      setLoginError("Passwords do not match.");
      return;
    }
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) {
      setLoginError("This number is already registered.");
      return;
    }
    users[phone] = { password, name: '', profilePic: '' };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    localStorage.setItem('rajquiz_currentUser', phone);
    loginUser(phone, '', '');
    setLoginError('');
  };

  const handleUpdateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) {
      users[phone].name = editName;
      users[phone].profilePic = editProfilePic || '';
      localStorage.setItem('rajquiz_users', JSON.stringify(users));
      setCurrentUser(prev => prev ? { ...prev, name: editName, profilePic: editProfilePic || '' } : null);
      alert("Profile updated successfully!");
      navigateTo(AppView.PROFILE);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setEditProfilePic(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 45, completed: false,
        testId: options.testId || `${type}_${Date.now()}`
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      console.error("Quiz Start Error:", err);
      alert("Database error. Please refresh and try again in a few moments.");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    const percentage = Math.max(0, (score / (session.questions.length * 2)) * 100);
    if (session.testId) saveProgress(session.testId, percentage);
    setLastResults({ score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, session } as any);
    navigateTo(AppView.SCORECARD);
  };

  const handleLogout = () => {
    localStorage.removeItem('rajquiz_currentUser');
    setIsLoggedIn(false);
    setCurrentUser(null);
    navigateTo(AppView.AUTH);
  };

  const renderBackButton = (target: AppView = AppView.HOME) => (
    <button onClick={() => navigateTo(target)} className="mb-6 flex items-center gap-2 text-slate-400 font-black hover:text-blue-600 transition-colors uppercase tracking-widest text-xs">
      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
      Back
    </button>
  );

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onTopicTestsClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)}
      onExamPapersClick={() => navigateTo(AppView.EXAM_MENU)}
      onBookmarksClick={() => navigateTo(AppView.BOOKMARKS)}
      onProfileClick={() => navigateTo(AppView.PROFILE)} 
      onLogout={handleLogout}
      isLoggedIn={isLoggedIn}
      userName={currentUser?.name}
      profilePic={currentUser?.profilePic}
    >
      {loading ? (
        <div className="min-h-[60vh] flex flex-col items-center justify-center animate-fadeIn text-center p-8">
          <div className="w-20 h-20 border-[6px] border-blue-600 border-t-transparent rounded-full animate-spin mb-8"></div>
          <h2 className="text-2xl font-black uppercase text-slate-900 mb-2 tracking-tighter">PREPARING TEST...</h2>
          <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">Accessing RPSC/RSSB Official Database</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && (
            <div className="min-h-[70vh] flex items-center justify-center p-4">
              <div className="bg-white p-10 md:p-14 rounded-[3.5rem] shadow-2xl w-full max-w-md animate-fadeIn border border-slate-100">
                {authStep === AuthSubView.CHOICE ? (
                  <div className="text-center space-y-12">
                    <div className="space-y-2">
                      <h2 className="text-5xl font-black text-blue-600 italic tracking-tighter">RAJQUIZER.</h2>
                      <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Target Selection 2024-2026</p>
                    </div>
                    <div className="space-y-4">
                      <button 
                        onClick={() => setAuthStep(AuthSubView.LOGIN)} 
                        className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95"
                      >
                        LOGIN
                      </button>
                      <button 
                        onClick={() => setAuthStep(AuthSubView.SIGNUP)} 
                        className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg shadow-lg hover:bg-slate-800 transition-all active:scale-95"
                      >
                        CREATE ACCOUNT
                      </button>
                    </div>
                  </div>
                ) : (
                  <form onSubmit={authStep === AuthSubView.LOGIN ? handleLogin : handleSignup} className="space-y-5">
                    <div className="flex items-center gap-4 mb-8">
                       <button 
                        type="button" 
                        onClick={() => { setAuthStep(AuthSubView.CHOICE); setLoginError(''); }} 
                        className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-white border border-slate-100 transition-all"
                       >
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7"/></svg>
                       </button>
                       <h3 className="text-3xl font-black tracking-tight">{authStep === AuthSubView.LOGIN ? 'Welcome back' : 'Start Today'}</h3>
                    </div>

                    <div className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Mobile Number</label>
                        <input 
                          type="tel" 
                          value={phone} 
                          onChange={e => setPhone(e.target.value)} 
                          placeholder="98xxxxxx00" 
                          className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold transition-all" 
                          required 
                        />
                      </div>

                      <div className="space-y-1">
                        <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Password</label>
                        <input 
                          type="password" 
                          value={password} 
                          onChange={e => setPassword(e.target.value)} 
                          placeholder="••••••••" 
                          className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold transition-all" 
                          required 
                        />
                      </div>

                      {authStep === AuthSubView.SIGNUP && (
                        <div className="space-y-1">
                          <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Confirm Password</label>
                          <input 
                            type="password" 
                            value={confirmPassword} 
                            onChange={e => setConfirmPassword(e.target.value)} 
                            placeholder="••••••••" 
                            className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold transition-all" 
                            required 
                          />
                        </div>
                      )}
                    </div>

                    {loginError && (
                      <div className="bg-rose-50 border border-rose-100 p-4 rounded-xl animate-shake">
                        <p className="text-rose-600 text-[11px] font-black uppercase leading-tight">{loginError}</p>
                      </div>
                    )}

                    <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg mt-4 shadow-xl shadow-blue-100 active:scale-95 transition-transform">
                      {authStep === AuthSubView.LOGIN ? 'LOG IN' : 'JOIN NOW'}
                    </button>

                    <p className="text-center text-slate-400 font-bold text-xs mt-4">
                      {authStep === AuthSubView.LOGIN ? "Don't have an account? " : "Already registered? "}
                      <button 
                        type="button" 
                        onClick={() => { setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN); setLoginError(''); }} 
                        className="text-blue-600 uppercase tracking-widest font-black"
                      >
                        {authStep === AuthSubView.LOGIN ? 'Sign Up' : 'Login'}
                      </button>
                    </p>
                  </form>
                )}
              </div>
            </div>
          )}

          {view === AppView.HOME && (
             <div className="space-y-16 animate-fadeIn py-10 max-w-6xl mx-auto px-4">
               <div className="text-center space-y-4">
                 <h1 className="text-6xl md:text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">TARGET <span className="text-blue-600">SELECTION.</span></h1>
                 <p className="text-slate-400 font-bold text-lg max-w-2xl mx-auto">Premium Rajasthan Official PYQ Database 2015-2026 for RPSC & RSSB Aspirants.</p>
               </div>
               <div className="grid md:grid-cols-3 gap-8">
                 {[
                   { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Full length sets." },
                   { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-blue-600 to-indigo-800", desc: "Subject-wise mastery." },
                   { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-emerald-500 to-teal-800", desc: "Original papers." }
                 ].map(card => (
                   <button key={card.title} onClick={card.onClick} className={`p-12 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white shadow-xl hover:-translate-y-2 transition-all group relative overflow-hidden active:scale-[0.98]`}>
                     <div className="relative z-10">
                        <h3 className="text-3xl font-black mb-1 uppercase">{card.title}</h3>
                        <p className="text-white/60 font-bold text-sm mb-8">{card.desc}</p>
                        <div className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">Explore <svg className="w-4 h-4 group-hover:translate-x-2 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></div>
                     </div>
                     <div className="absolute -right-4 -bottom-4 w-24 h-24 bg-white/5 rounded-full group-hover:scale-150 transition-transform"></div>
                   </button>
                 ))}
               </div>
             </div>
          )}

          {view === AppView.QUIZ_MIX_MENU && (
             <div className="max-w-6xl mx-auto px-4">
                {renderBackButton()}
                <div className="mb-10">
                   <h2 className="text-4xl font-black uppercase tracking-tighter mb-2">Mixed <span className="text-blue-600">Practice</span></h2>
                   <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">200 UNIQUE SETS • NO REPETITION GUARANTEED</p>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4 h-[60vh] overflow-y-auto pr-2 custom-scrollbar p-2">
                   {Array.from({ length: 200 }).map((_, i) => {
                     const testId = `mix_set_${i + 1}`;
                     const progress = userProgress[testId] || 0;
                     const isAttempted = progress > 0;
                     return (
                        <button 
                          key={i} 
                          onClick={() => startQuiz(QuizType.MIX, `Mixed GK Practice Set #${i + 1}`, { count: 25, isMix: true, testNumber: i + 1, testId })} 
                          className={`bg-white p-6 rounded-3xl border ${isAttempted ? 'border-emerald-200' : 'border-slate-100'} shadow-sm hover:shadow-xl hover:border-blue-300 transition-all text-left relative group overflow-hidden active:scale-95`}
                        >
                           <div className="flex justify-between items-start mb-1">
                              <span className="text-slate-300 font-black text-[10px] uppercase">SET {i+1}</span>
                              {isAttempted && (
                                <div className="text-emerald-500">
                                  <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                                </div>
                              )}
                           </div>
                           <h4 className="text-lg font-bold mb-4 text-slate-700">Practice Mock</h4>
                           <div className="flex items-center justify-between">
                              <div className="text-[8px] font-black uppercase text-blue-600 bg-blue-50 px-2 py-1 rounded">25 Qs</div>
                              {isAttempted && <div className="text-[8px] font-black text-emerald-600">{Math.round(progress)}% Score</div>}
                           </div>
                           <div className={`absolute bottom-0 left-0 h-1 ${isAttempted ? 'bg-emerald-500' : 'bg-blue-600'} transition-all group-hover:w-full`} style={{ width: `${progress}%` }}></div>
                        </button>
                     );
                   })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_TOPIC_MENU && (
             <div className="max-w-5xl mx-auto px-4">
                {renderBackButton()}
                <h2 className="text-4xl font-black mb-10 uppercase tracking-tighter">Browse <span className="text-blue-600">Subjects</span></h2>
                <div className="grid sm:grid-cols-2 gap-6">
                   {TOPIC_GROUPS.map(group => (
                     <button key={group.id} onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl hover:bg-slate-50 transition-all text-left group active:scale-[0.98]">
                       <h3 className="text-2xl font-bold mb-2 group-hover:text-blue-600 transition-colors">{group.name}</h3>
                       <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">{group.subtopics.length} Targeted Sub-topics</p>
                     </button>
                   ))}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_SUBTOPIC_MENU && selectedGroup && (
             <div className="max-w-5xl mx-auto px-4">
                {renderBackButton(AppView.QUIZ_TOPIC_MENU)}
                <h2 className="text-4xl font-black mb-10 uppercase tracking-tighter">{selectedGroup.name}</h2>
                <div className="grid gap-3">
                   {selectedGroup.subtopics.map((sub, i) => {
                     const testId = `topic_${selectedGroup.id}_${i}`;
                     const progress = userProgress[testId] || 0;
                     const isAttempted = progress > 0;
                     return (
                       <button key={i} onClick={() => startQuiz(QuizType.TOPIC, sub, { count: 25, topic: sub, subject: selectedGroup.name, testId })} className={`bg-white p-6 rounded-2xl border ${isAttempted ? 'border-emerald-200' : 'border-slate-100'} shadow-sm hover:border-blue-600 transition-all text-left flex items-center justify-between group active:scale-[0.99]`}>
                          <div className="flex items-center gap-3">
                             {isAttempted && <svg className="w-5 h-5 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>}
                             <span className="text-lg font-bold hindi-text text-slate-700">{sub}</span>
                          </div>
                          <div className="flex items-center gap-4">
                             {isAttempted && <span className="text-[10px] font-black text-emerald-600">{Math.round(progress)}% Score</span>}
                             <svg className="w-5 h-5 text-slate-200 group-hover:text-blue-600 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6"/></svg>
                          </div>
                       </button>
                     );
                   })}
                </div>
             </div>
          )}

          {view === AppView.EXAM_MENU && (
             <div className="max-w-6xl mx-auto px-4">
                {renderBackButton()}
                <div className="flex flex-col md:flex-row justify-between mb-12 gap-6">
                   <h2 className="text-4xl font-black uppercase tracking-tighter">Official <span className="text-blue-600">Papers</span></h2>
                   <div className="relative w-full md:w-80">
                      <input type="text" placeholder="Search Exam..." value={examSearch} onChange={e => setExamSearch(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" />
                      <svg className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
                   </div>
                </div>
                <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
                   {OFFICIAL_EXAMS.filter(e => e.name.toLowerCase().includes(examSearch.toLowerCase())).map((exam, i) => {
                      const testId = `exam_${exam.name}_${exam.year}`;
                      const progress = userProgress[testId] || 0;
                      const isAttempted = progress > 0;
                      return (
                        <button key={i} onClick={() => startQuiz(QuizType.EXAM, exam.name, { count: exam.count, examContext: exam.context, testId })} className={`bg-white p-10 rounded-[3rem] border ${isAttempted ? 'border-emerald-200' : 'border-slate-100'} shadow-sm hover:shadow-2xl transition-all text-left flex flex-col justify-between group h-full active:scale-[0.98]`}>
                           <div>
                              <div className="flex justify-between mb-4">
                                 <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full font-black text-[10px] uppercase">{exam.tag}</span>
                                 <div className="flex items-center gap-2">
                                    {isAttempted && <svg className="w-4 h-4 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>}
                                    <span className="text-slate-300 font-black">{exam.year}</span>
                                 </div>
                              </div>
                              <h3 className="text-2xl font-black mb-2 leading-tight text-slate-800">{exam.name}</h3>
                              <p className="text-slate-400 font-bold text-sm">{exam.count} Questions</p>
                           </div>
                           <div className="flex items-center justify-between pt-8">
                              <div className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-2">Start Paper <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6"/></svg></div>
                              {isAttempted && <div className="text-[10px] font-black text-emerald-600">{Math.round(progress)}% Score</div>}
                           </div>
                        </button>
                      );
                   })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_ACTIVE && activeSession && (
            <QuizEngine session={activeSession} onComplete={onQuizComplete} onExit={() => navigateTo(AppView.HOME)} onToggleBookmark={toggleBookmark} bookmarkedIds={bookmarks.map(b => b.id)} />
          )}

          {view === AppView.SCORECARD && lastResults && (
            <ScoreCard results={lastResults} onReview={() => navigateTo(AppView.REVIEW)} onNextTest={() => navigateTo(AppView.HOME)} onBackHome={() => navigateTo(AppView.HOME)} />
          )}

          {view === AppView.REVIEW && lastResults && (
            <QuizEngine session={lastResults.session} onComplete={() => navigateTo(AppView.HOME)} onExit={() => navigateTo(AppView.SCORECARD)} isReview={true} onToggleBookmark={toggleBookmark} bookmarkedIds={bookmarks.map(b => b.id)} />
          )}

          {view === AppView.BOOKMARKS && (
            <div className="max-w-4xl mx-auto px-4">
               {renderBackButton()}
               <h2 className="text-4xl font-black mb-10 uppercase tracking-tighter">Saved <span className="text-rose-600">Questions</span></h2>
               {bookmarks.length === 0 ? (
                 <div className="bg-white p-20 rounded-[3rem] text-center border-2 border-dashed border-slate-100 text-slate-300 font-black uppercase">No Bookmarks Saved</div>
               ) : (
                 <div className="grid gap-6">
                    {bookmarks.map(q => (
                      <div key={q.id} className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm relative animate-fadeIn">
                         <button onClick={() => toggleBookmark(q)} className="absolute top-8 right-8 text-rose-600 font-black text-xs uppercase hover:underline">Remove</button>
                         <h3 className="text-xl font-bold mb-6 hindi-text pr-16 text-slate-800">{q.question}</h3>
                         <div className="grid gap-2">
                            {['A','B','C','D'].map(key => (
                               <div key={key} className={`p-4 rounded-xl border-2 flex items-center gap-4 ${q.correctAnswer === key ? 'bg-emerald-50 border-emerald-500' : 'border-slate-100'}`}>
                                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black ${q.correctAnswer === key ? 'bg-emerald-600 text-white' : 'bg-slate-50 text-slate-300'}`}>{key}</div>
                                  <span className="hindi-text font-bold text-slate-700">{q.options[key as 'A'|'B'|'C'|'D']}</span>
                               </div>
                            ))}
                         </div>
                      </div>
                    ))}
                 </div>
               )}
            </div>
          )}

          {view === AppView.PROFILE && (
            <div className="max-w-2xl mx-auto animate-fadeIn px-4">
              {renderBackButton()}
              <div className="bg-white p-12 rounded-[3.5rem] shadow-xl text-center border border-slate-100">
                <div className="w-32 h-32 bg-blue-600 rounded-full mx-auto mb-6 flex items-center justify-center text-white overflow-hidden border-4 border-white shadow-lg relative group">
                   {currentUser?.profilePic ? <img src={currentUser.profilePic} className="w-full h-full object-cover" /> : <svg className="w-16 h-16" fill="currentColor" viewBox="0 0 24 24"><path d="M7.5 6a4.5 4.5 0 119 0 4.5 4.5 0 01-9 0zM3.751 20.105a8.25 8.25 0 0116.498 0 .75.75 0 01-.437.695A18.683 18.683 0 0112 22.5c-2.786 0-5.433-.608-7.812-1.7a.75.75 0 01-.437-.695z" /></svg>}
                </div>
                <h3 className="text-3xl font-black mb-1 text-slate-900">{currentUser?.name || 'Aspirant'}</h3>
                <p className="text-slate-400 font-bold mb-8">{phone}</p>
                <div className="grid grid-cols-2 gap-4 mb-8">
                   <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <span className="text-2xl font-black text-slate-800">{Object.keys(userProgress).length}</span>
                      <span className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Tests Done</span>
                   </div>
                   <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <span className="text-2xl font-black text-slate-800">{bookmarks.length}</span>
                      <span className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Bookmarks</span>
                   </div>
                </div>
                <div className="space-y-3">
                   <button onClick={() => navigateTo(AppView.EDIT_PROFILE)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg active:scale-95">Edit Profile</button>
                   <button onClick={handleLogout} className="w-full py-4 text-rose-600 font-black text-sm uppercase tracking-widest hover:bg-rose-50 rounded-2xl transition-colors">Logout</button>
                </div>
              </div>
            </div>
          )}

          {view === AppView.EDIT_PROFILE && (
            <div className="max-w-2xl mx-auto animate-fadeIn px-4">
              {renderBackButton(AppView.PROFILE)}
              <div className="bg-white p-12 rounded-[3.5rem] shadow-xl border border-slate-100">
                 <h3 className="text-3xl font-black mb-10 text-center">Update <span className="text-blue-600">Profile</span></h3>
                 <form onSubmit={handleUpdateProfile} className="space-y-6">
                    <div className="flex flex-col items-center mb-10">
                       <div className="relative cursor-pointer group" onClick={() => fileInputRef.current?.click()}>
                          <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center overflow-hidden border-2 border-slate-200 group-hover:border-blue-500 transition-all">
                             {editProfilePic ? <img src={editProfilePic} className="w-full h-full object-cover" /> : <svg className="w-10 h-10 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M12 9a3 3 0 100 6 3 3 0 000-6z" /><path fillRule="evenodd" d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zM4 12a8 8 0 1116 0 8 8 0 01-16 0z" /></svg>}
                          </div>
                          <div className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                             <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
                          </div>
                          <input ref={fileInputRef} type="file" className="hidden" onChange={handleFileChange} />
                       </div>
                       <p className="mt-4 text-[10px] font-black uppercase text-slate-400 tracking-widest">Click to change picture</p>
                    </div>
                    <input type="text" value={editName} onChange={e => setEditName(e.target.value)} placeholder="Full Name" className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" />
                    <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-100 active:scale-95 transition-transform">SAVE PROFILE</button>
                 </form>
              </div>
            </div>
          )}
        </>
      )}
    </Layout>
  );
};

export default App;

export enum AppView {
  AUTH = 'auth',
  HOME = 'home',
  QUIZ_MENU = 'quiz_menu',
  QUIZ_MIX_MENU = 'quiz_mix_menu',
  QUIZ_TOPIC_MENU = 'quiz_topic_menu',
  QUIZ_SUBTOPIC_MENU = 'quiz_subtopic_menu',
  QUIZ_TOPIC_TESTS_MENU = 'quiz_topic_tests_menu',
  EXAM_MENU = 'exam_menu',
  AI_TEST = 'ai_test',
  QUIZ_ACTIVE = 'quiz_active',
  SCORECARD = 'scorecard',
  REVIEW = 'review',
  PROFILE = 'profile',
  EDIT_PROFILE = 'edit_profile',
  BOOKMARKS = 'bookmarks'
}

export enum AuthSubView {
  CHOICE = 'choice',
  LOGIN = 'login',
  SIGNUP = 'signup',
  FORGOT_PHONE = 'forgot_phone',
  FORGOT_OTP = 'forgot_otp',
  RESET_PASSWORD = 'reset_password'
}

export enum QuizType {
  MIX = 'mix',
  TOPIC = 'topic',
  EXAM = 'exam',
  AI = 'ai'
}

export interface User {
  phone: string;
  name?: string;
  password?: string;
  profilePic?: string; // Base64 image string
}

export interface Question {
  id: string;
  question: string;
  options: {
    A: string;
    B: string;
    C: string;
    D: string;
    E: string;
  };
  correctAnswer: 'A' | 'B' | 'C' | 'D' | 'E';
  examName: string;
  examYear: number;
  subject: string;
  topic?: string;
}

export interface QuizSession {
  type: QuizType;
  title: string;
  questions: Question[];
  currentQuestionIndex: number;
  userAnswers: Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>;
  startTime: number;
  durationInMinutes: number;
  completed: boolean;
  testId?: string;
}

export interface QuizResults {
  score: number;
  correctCount: number;
  incorrectCount: number;
  skippedCount: number;
  unattemptedCount: number;
  totalQuestions: number;
  timeTaken: string;
  session: QuizSession;
}

export interface AttemptRecord {
  id: string;
  title: string;
  score: number;
  maxScore: number;
  date: number;
  correct: number;
  total: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question,
  User
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [editName, setEditName] = useState('');
  const [editProfilePic, setEditProfilePic] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadingStatus, setLoadingStatus] = useState('Initializing Archive...');
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [selectedSubtopicIdx, setSelectedSubtopicIdx] = useState<number>(-1);

  const [examSearch, setExamSearch] = useState('');
  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUserPhone = localStorage.getItem('rajquiz_currentUser');
    if (savedUserPhone) {
      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      const userData = users[savedUserPhone];
      if (userData) {
        loginUser(savedUserPhone, userData.name, userData.profilePic);
      } else {
        setView(AppView.AUTH);
      }
    } else {
      setView(AppView.AUTH);
    }
  }, []);

  const loginUser = (userPhone: string, userName?: string, profilePic?: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setCurrentUser({ phone: userPhone, name: userName, profilePic });
    setEditName(userName || '');
    setEditProfilePic(profilePic || null);
    setView(AppView.HOME);

    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testId: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const newProgress = { ...userProgress, [testId]: Math.max(userProgress[testId] || 0, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { 
      setLoginError("Account not found. Redirecting to Signup..."); 
      setTimeout(() => {
        setAuthStep(AuthSubView.SIGNUP);
        setLoginError('');
      }, 1500);
      return; 
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone, user.name, user.profilePic);
      setLoginError('');
    } else { 
      setLoginError("Invalid password. Please try again."); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) {
      setLoginError("Enter a valid 10-digit mobile number.");
      return;
    }
    if (password !== confirmPassword) {
      setLoginError("Passwords do not match.");
      return;
    }
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) {
      setLoginError("This number is already registered. Please Login.");
      return;
    }
    users[phone] = { password, name: '', profilePic: '' };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    localStorage.setItem('rajquiz_currentUser', phone);
    loginUser(phone, '', '');
    setLoginError('');
  };

  const handleUpdateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) {
      users[phone].name = editName;
      users[phone].profilePic = editProfilePic || '';
      localStorage.setItem('rajquiz_users', JSON.stringify(users));
