      reader.onloadend = () => setEditProfilePic(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    setLoading(true);
    setLoadingStatus('Connecting to RPSC/RSSB Archives...');

    const statuses = [
      'Authenticating Data Sources...',
      'Filtering Previous Year Questions...',
      'Verifying Answer Keys...',
      'Assembling Your Test...'
    ];
    let statusIdx = 0;
    const statusInterval = setInterval(() => {
      setLoadingStatus(statuses[statusIdx % statuses.length]);
      statusIdx++;
    }, 2000);

    try {
      const questions = await fetchPYQs({ ...options, count: options.count || 25 });
      clearInterval(statusInterval);
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0,
        userAnswers: {}, startTime: Date.now(), durationInMinutes: options.count >= 100 ? 120 : 45, completed: false,
        testId: options.testId || `${type}_${Date.now()}`
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      clearInterval(statusInterval);
      console.error("Quiz Start Error:", err);
      alert("Unable to load quiz. Check your connection and try again.");
      setLoading(false);
    }
  }, []);

