                          <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest px-1">Confirm Password</label>
                          <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="••••••••" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold transition-all" required />
                        </div>
                      )}
                    </div>
                    {loginError && (
                      <div className="bg-rose-50 border border-rose-100 p-4 rounded-xl">
                        <p className="text-rose-600 text-[11px] font-black uppercase">{loginError}</p>
                      </div>
                    )}
                    <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg mt-4 shadow-xl active:scale-95 transition-all">
                      {authStep === AuthSubView.LOGIN ? 'LOG IN' : 'CREATE ACCOUNT'}
                    </button>
                    <p className="text-center text-slate-400 font-bold text-xs mt-4">
                      {authStep === AuthSubView.LOGIN ? "New user? " : "Existing user? "}
                      <button type="button" onClick={() => { setAuthStep(authStep === AuthSubView.LOGIN ? AuthSubView.SIGNUP : AuthSubView.LOGIN); setLoginError(''); }} className="text-blue-600 uppercase tracking-widest font-black">
                        {authStep === AuthSubView.LOGIN ? 'Sign Up' : 'Login'}
                      </button>
                    </p>
                  </form>
                )}
              </div>
            </div>
          )}

          {view === AppView.HOME && (
