import React, { useState, useEffect } from 'react';
import { Question, QuizSession } from '../types.ts';
import { MARKING_SCHEME } from '../constants.ts';

interface QuizEngineProps {
  session: QuizSession;
  onComplete: (session: QuizSession) => void;
  onExit: () => void;
  isReview?: boolean;
  onToggleBookmark?: (q: Question) => void;
  bookmarkedIds?: string[];
}

const QuizEngine: React.FC<QuizEngineProps> = ({ 
  session, 
  onComplete, 
  onExit, 
  isReview = false,
  onToggleBookmark,
  bookmarkedIds = []
}) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>>(session.userAnswers);
  const [timeLeft, setTimeLeft] = useState(session.durationInMinutes * 60);

  useEffect(() => {
    if (isReview) return;
    if (timeLeft <= 0) {
      handleSubmit();
      return;
    }
    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isReview]);

  const handleSubmit = () => {
    onComplete({
      ...session,
      userAnswers: answers,
      completed: true
    });
  };

  const handleBackClick = () => {
    if (isReview) {
      onExit();
      return;
    }
    if (window.confirm("Do you want to exit the test?")) {
      onExit();
    }
  };

  const handleSelect = (option: 'A' | 'B' | 'C' | 'D' | 'E') => {
    if (isReview) return;
    const qId = session.questions[currentIdx].id;

    // STRICT RULE: Once an option is selected, it cannot be changed for this test session.
    if (answers[qId]) {
      return;
    }

    setAnswers(prev => ({ ...prev, [qId]: option }));

    // Auto-advance after selection
    if (currentIdx < session.questions.length - 1) {
      setTimeout(() => {
        setCurrentIdx(prev => prev + 1);
      }, 450);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const currentQ = session.questions[currentIdx];
  const userAns = answers[currentQ.id];
  const isBookmarked = bookmarkedIds.includes(currentQ.id);

  return (
    <div className="flex flex-col lg:flex-row gap-6 max-w-[1400px] mx-auto animate-fadeIn">
      <div className="flex-grow">
        <div className="glass sticky top-16 md:top-20 z-40 px-4 py-3 rounded-2xl shadow-sm border border-slate-200 mb-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-black text-xs whitespace-nowrap">
              Q {currentIdx + 1} / {session.questions.length}
            </span>
            {!isReview && (
              <div className={`flex items-center gap-1 font-mono text-lg font-bold ${timeLeft < 300 ? 'text-rose-600 animate-pulse' : 'text-slate-700'}`}>
                {formatTime(timeLeft)}
              </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={() => onToggleBookmark?.(currentQ)}
                className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-all ${isBookmarked ? 'bg-rose-50 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600'}`}
             >
                <svg className="w-5 h-5" fill={isBookmarked ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" /></svg>
             </button>
             <button onClick={handleBackClick} className="w-10 h-10 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
             </button>
          </div>
        </div>

        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-slate-100 min-h-[400px] mb-6 animate-fadeIn relative overflow-hidden">
          <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>
          <div className="mb-8">
            <div className="flex items-center gap-2 mb-4">
               <span className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-600 bg-blue-50 px-3 py-1 rounded-full">Official Paper</span>
               <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">{currentQ.examName} ({currentQ.examYear})</span>
            </div>
            <h2 className="text-2xl md:text-3xl font-bold hindi-text leading-relaxed text-slate-800">
              {currentQ.question}
            </h2>
          </div>

          <div className="grid gap-3">
            {(['A', 'B', 'C', 'D', 'E'] as const).map((key) => {
              const isCorrect = isReview && currentQ.correctAnswer === key;
              const isSelected = userAns === key;
              const isWrongSelection = isReview && isSelected && !isCorrect;
              const isLocked = !!userAns && !isReview;

              let cardClasses = "relative w-full p-5 rounded-2xl border-2 flex items-center gap-4 transition-all text-left group ";

              if (isReview) {
                if (isCorrect) cardClasses += "bg-emerald-50 border-emerald-500 shadow-md";
                else if (isWrongSelection) cardClasses += "bg-rose-50 border-rose-500 shadow-md";
                else cardClasses += "bg-white border-slate-100 opacity-60";
              } else {
                if (isSelected) cardClasses += "bg-blue-50 border-blue-600 shadow-lg";
                else if (isLocked) cardClasses += "bg-slate-50 border-slate-100 opacity-60 grayscale cursor-not-allowed";
                else cardClasses += "bg-white border-slate-100 hover:border-blue-300 active:scale-[0.99]";
              }

              return (
                <button 
                  key={key} 
                  disabled={isLocked || isReview}
                  onClick={() => handleSelect(key)} 
                  className={cardClasses}
                >
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-sm shrink-0 transition-colors ${
                    isCorrect ? 'bg-emerald-600 text-white' : 
                    isWrongSelection ? 'bg-rose-600 text-white' : 
                    isSelected ? 'bg-blue-600 text-white' : 
                    'bg-slate-50 text-slate-400 group-hover:bg-blue-100 group-hover:text-blue-600'
                  }`}>
                    {key}
                  </div>
                  <span className={`hindi-text font-bold text-lg ${
                    isCorrect ? 'text-emerald-900' : 
                    isWrongSelection ? 'text-rose-900' : 
                    isSelected ? 'text-blue-900' : 
                    'text-slate-600'
                  }`}>
                    {currentQ.options[key]}
                  </span>
                </button>
              );
            })}
          </div>
        </div>

        <div className="flex items-center justify-between mb-12">
           <button 
              onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))}
              disabled={currentIdx === 0}
              className="px-6 py-3 rounded-2xl bg-white border border-slate-200 text-slate-500 font-black text-xs uppercase tracking-widest hover:bg-slate-50 disabled:opacity-30 transition-all flex items-center gap-2"
           >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7"/></svg>
              Prev
           </button>

           <div className="hidden md:flex items-center gap-2">
              {userAns && <div className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100">Answer Locked</div>}
           </div>

           {currentIdx === session.questions.length - 1 ? (
             <button 
                onClick={handleSubmit}
                className="px-8 py-3 rounded-2xl bg-slate-900 text-white font-black text-xs uppercase tracking-[0.2em] hover:bg-slate-800 shadow-xl transition-all"
             >
                Finish
             </button>
           ) : (
             <button 
                onClick={() => setCurrentIdx(prev => Math.min(session.questions.length - 1, prev + 1))}
                className="px-6 py-3 rounded-2xl bg-white border border-slate-200 text-blue-600 font-black text-xs uppercase tracking-widest hover:bg-blue-50 transition-all flex items-center gap-2"
             >
                Next
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7"/></svg>
             </button>
           )}
        </div>
      </div>

      <div className="w-full lg:w-80 shrink-0">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 sticky top-20">
          <h3 className="text-sm font-black uppercase tracking-widest text-slate-400 mb-6 px-2">Progress Map</h3>
          <div className="grid grid-cols-5 gap-2 h-[400px] overflow-y-auto pr-2 custom-scrollbar p-1">
            {session.questions.map((q, idx) => {
              const isAns = !!answers[q.id];
              const isCurrent = idx === currentIdx;
              let dotClass = "w-10 h-10 rounded-xl flex items-center justify-center font-bold text-xs transition-all ";

              if (isReview) {
                const correct = answers[q.id] === q.correctAnswer;
                const skipped = answers[q.id] === 'E' || !answers[q.id];
                if (correct) dotClass += "bg-emerald-500 text-white";
                else if (skipped) dotClass += "bg-slate-100 text-slate-400";
                else dotClass += "bg-rose-500 text-white";
              } else {
                if (isCurrent) dotClass += "ring-4 ring-blue-100 bg-blue-600 text-white shadow-lg";
                else if (isAns) dotClass += "bg-slate-800 text-white";
                else dotClass += "bg-slate-50 text-slate-300 hover:bg-slate-100";
              }

              return (
                <button 
                  key={idx} 
                  onClick={() => setCurrentIdx(idx)}
                  className={dotClass}
                >
                  {idx + 1}
                </button>
              );
            })}
          </div>

          {!isReview && (
            <div className="mt-8 pt-6 border-t border-slate-100 space-y-4">
               <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest px-2">
                  <span className="text-slate-400">Answered</span>
                  <span className="text-slate-800 font-black">{Object.keys(answers).length} / {session.questions.length}</span>
               </div>
               <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                  <div className="bg-blue-600 h-full transition-all duration-500" style={{ width: `${(Object.keys(answers).length / session.questions.length) * 100}%` }}></div>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

