          <h2 className="text-3xl font-black uppercase text-slate-900 mb-2 tracking-tighter italic">Fetching 50 PYQs...</h2>
          <p className="text-blue-600 font-bold uppercase text-[10px] tracking-[0.3em]">Authentic Resource Archive</p>
        </div>
      ) : (
        <>
          {view === AppView.AUTH && (
