                 <p className="text-slate-400 font-bold text-lg max-w-2xl mx-auto">Access Verified RPSC & RSSB PYQs. Every single test features 50 high-quality questions.</p>
               </div>
               <div className="grid md:grid-cols-3 gap-8">
                 {[
                   { title: "Mixed Mocks", onClick: () => navigateTo(AppView.QUIZ_MIX_MENU), gradient: "from-slate-800 to-slate-950", desc: "200 Practice Sets (50 Qs)" },
                   { title: "Topic Wise", onClick: () => navigateTo(AppView.QUIZ_TOPIC_MENU), gradient: "from-blue-600 to-indigo-800", desc: "Subject Focus (50 Qs)" },
                   { title: "Exam Papers", onClick: () => navigateTo(AppView.EXAM_MENU), gradient: "from-emerald-600 to-teal-800", desc: "Official Paper Archives" }
