                   <button key={card.title} onClick={card.onClick} className={`p-12 rounded-[3.5rem] text-left bg-gradient-to-br ${card.gradient} text-white shadow-xl hover:-translate-y-2 transition-all group active:scale-[0.98]`}>
                     <div className="relative z-10">
                        <h3 className="text-3xl font-black mb-1 uppercase tracking-tight">{card.title}</h3>
