                              <span className={`inline-block mb-4 px-3 py-1 rounded-full font-black text-[10px] uppercase ${isAttempted ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>SET {i+1}</span>
