                              ) : (
                                <svg className="w-10 h-10 text-slate-100 group-hover:text-blue-100" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                              )}
                           </div>
                           <div className={`absolute bottom-0 left-0 h-1.5 ${isAttempted ? 'bg-emerald-500' : 'bg-blue-600'} transition-all group-hover:w-full`} style={{ width: `${progress}%` }}></div>
                        </button>
                     );
                   })}
                </div>
             </div>
          )}

          {view === AppView.REVEAL_ALL && lastResults && (
            <div className="max-w-4xl mx-auto px-4 animate-fadeIn pb-20">
               <div className="sticky top-20 bg-white/80 backdrop-blur-md z-40 py-6 border-b border-slate-100 flex items-center justify-between mb-10">
                  <div>
                    <h2 className="text-3xl font-black uppercase tracking-tighter">Answer <span className="text-amber-500">Key</span></h2>
                    <p className="text-slate-400 font-bold text-[10px] uppercase tracking-widest">{lastResults.session.title}</p>
                  </div>
                  <button onClick={() => navigateTo(AppView.SCORECARD)} className="px-6 py-2 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest">Back to Results</button>
               </div>
               <div className="space-y-8">
                  {lastResults.session.questions.map((q, idx) => (
                    <div key={q.id} className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm relative overflow-hidden">
                       <div className="absolute top-0 left-0 w-1.5 h-full bg-slate-100"></div>
                       <div className="flex items-center gap-3 mb-6">
                          <span className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-sm">{idx + 1}</span>
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{q.examName} ({q.examYear})</span>
