                                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black ${isCorrect ? 'bg-emerald-600 text-white' : 'bg-slate-200 text-slate-500'}`}>{key}</div>
                                  <span className="hindi-text font-bold text-slate-800">{q.options[key as 'A'|'B'|'C'|'D'|'E']}</span>
                                  {isCorrect && <span className="ml-auto text-emerald-600 font-black text-[10px] uppercase tracking-widest">Correct Answer</span>}
                               </div>
                             );
                          })}
                       </div>
                    </div>
                  ))}
               </div>
               <div className="mt-12 text-center">
                  <button onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} className="text-blue-600 font-black uppercase tracking-widest text-xs">Scroll to Top ↑</button>
               </div>
            </div>
          )}

          {view === AppView.QUIZ_TOPIC_MENU && (
             <div className="max-w-5xl mx-auto px-4">
                {renderBackButton()}
                <h2 className="text-4xl font-black mb-10 uppercase tracking-tighter">Topic <span className="text-blue-600">Tests</span></h2>
                <div className="grid sm:grid-cols-2 gap-6">
                   {TOPIC_GROUPS.map(group => (
                     <button key={group.id} onClick={() => { setSelectedGroup(group); navigateTo(AppView.QUIZ_SUBTOPIC_MENU); }} className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl hover:bg-slate-50 transition-all text-left group">
                       <h3 className="text-2xl font-bold mb-2 group-hover:text-blue-600 transition-colors">{group.name}</h3>
                       <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">{group.subtopics.length} Targeted Topics</p>
                     </button>
                   ))}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_SUBTOPIC_MENU && selectedGroup && (
             <div className="max-w-5xl mx-auto px-4">
                {renderBackButton(AppView.QUIZ_TOPIC_MENU)}
                <h2 className="text-4xl font-black mb-10 uppercase tracking-tighter">{selectedGroup.name}</h2>
                <div className="grid gap-3">
                   {selectedGroup.subtopics.map((sub, i) => {
                     const isDone = (userProgress[`topic_${selectedGroup.id}_${i}_test1`] || 0) > 0;
                     return (
                       <button key={i} onClick={() => { setSelectedSubtopic(sub); setSelectedSubtopicIdx(i); navigateTo(AppView.QUIZ_TOPIC_TESTS_MENU); }} className={`bg-white p-6 rounded-2xl border-2 ${isDone ? 'border-emerald-200 shadow-sm' : 'border-slate-100'} hover:border-blue-600 transition-all text-left flex items-center justify-between group`}>
                          <div className="flex items-center gap-3">
                             {isDone && <span className="text-emerald-500 font-bold">✅</span>}
                             <span className="text-lg font-bold hindi-text text-slate-700">{sub}</span>
                          </div>
                          <svg className="w-5 h-5 text-slate-200 group-hover:text-blue-600 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7l5 5m0 0l-5 5m5-5H6"/></svg>
                       </button>
                     );
                   })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_TOPIC_TESTS_MENU && selectedSubtopic && selectedGroup && (
            <div className="max-w-4xl mx-auto px-4">
              {renderBackButton(AppView.QUIZ_SUBTOPIC_MENU)}
              <h2 className="text-3xl font-black mb-2 uppercase tracking-tight">{selectedSubtopic}</h2>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mb-10">Select a unique 50-question test set</p>
              <div className="grid sm:grid-cols-2 gap-8">
                {[1, 2].map(num => {
