               </div>
             </div>
          )}

          {view === AppView.QUIZ_MIX_MENU && (
             <div className="max-w-6xl mx-auto px-4">
                {renderBackButton()}
                <div className="mb-10">
                   <h2 className="text-4xl font-black uppercase tracking-tighter mb-2">Practice <span className="text-blue-600">Sets</span></h2>
                   <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">200 UNIQUE SETS • CLICK TO LOAD INSTANTLY</p>
                </div>
                {/* LARGER GRID FOR SETS */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 h-[65vh] overflow-y-auto pr-4 custom-scrollbar p-2 pb-20">
                   {Array.from({ length: 200 }).map((_, i) => {
                     const testId = `mix_set_${i + 1}`;
                     const progress = userProgress[testId] || 0;
                     const isAttempted = progress > 0;
                     const isCached = !!localStorage.getItem(`rajquiz_cache_${testId}`);

                     return (
                        <button key={i} onClick={() => startQuiz(QuizType.MIX, `Mixed Mock Set #${i + 1}`, { count: 50, isMix: true, testNumber: i + 1, testId })} className={`bg-white p-10 rounded-[3rem] border-2 ${isAttempted ? 'border-emerald-200' : isCached ? 'border-blue-100' : 'border-slate-100'} shadow-sm hover:shadow-2xl hover:border-blue-600 transition-all text-left relative group overflow-hidden active:scale-95 flex items-center justify-between`}>
                           <div className="flex gap-8 items-center">
                              <div className={`w-20 h-20 rounded-3xl flex items-center justify-center font-black text-3xl shrink-0 ${isAttempted ? 'bg-emerald-50 text-emerald-600' : isCached ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-300'}`}>
