import React, { useState, useEffect } from 'react';
import { Question, QuizSession } from '../types.ts';
import { MARKING_SCHEME } from '../constants.ts';

interface QuizEngineProps {
  session: QuizSession;
  onComplete: (session: QuizSession) => void;
  onExit: () => void;
  isReview?: boolean;
  onToggleBookmark?: (q: Question) => void;
  bookmarkedIds?: string[];
}

const QuizEngine: React.FC<QuizEngineProps> = ({ 
  session, 
  onComplete, 
  onExit, 
  isReview = false,
  onToggleBookmark,
  bookmarkedIds = []
}) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, 'A' | 'B' | 'C' | 'D' | 'E' | null>>(session.userAnswers);
  const [timeLeft, setTimeLeft] = useState(session.durationInMinutes * 60);

  useEffect(() => {
    if (isReview) return;
    if (timeLeft <= 0) {
      handleSubmit();
      return;
    }
    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);
    return () => clearInterval(timer);
  }, [timeLeft, isReview]);

  const handleSubmit = () => {
    onComplete({
      ...session,
      userAnswers: answers,
      completed: true
    });
  };

  const handleBackClick = () => {
    if (isReview) {
      onExit();
      return;
    }
    if (window.confirm("Do you want to exit the test?")) {
      onExit();
    }
  };

  const handleSelect = (option: 'A' | 'B' | 'C' | 'D' | 'E') => {
    if (isReview) return;
    const qId = session.questions[currentIdx].id;

    // STRICT RULE: Once an option is selected, it cannot be changed for this test session.
    if (answers[qId]) {
      return;
    }

    setAnswers(prev => ({ ...prev, [qId]: option }));

    // Auto-advance after selection
    if (currentIdx < session.questions.length - 1) {
      setTimeout(() => {
        setCurrentIdx(prev => prev + 1);
      }, 450);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const currentQ = session.questions[currentIdx];
  const userAns = answers[currentQ.id];
  const isBookmarked = bookmarkedIds.includes(currentQ.id);

  return (
    <div className="flex flex-col lg:flex-row gap-6 max-w-[1400px] mx-auto animate-fadeIn">
      <div className="flex-grow">
        <div className="glass sticky top-16 md:top-20 z-40 px-4 py-3 rounded-2xl shadow-sm border border-slate-200 mb-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <span className="bg-slate-900 text-white px-3 py-1 rounded-lg font-black text-xs whitespace-nowrap">
              Q {currentIdx + 1} / {session.questions.length}
            </span>
            {!isReview && (
              <div className={`flex items-center gap-1 font-mono text-lg font-bold ${timeLeft < 300 ? 'text-rose-600 animate-pulse' : 'text-slate-700'}`}>
                {formatTime(timeLeft)}
              </div>
            )}
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={() => onToggleBookmark?.(currentQ)}
                className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-all ${isBookmarked ? 'bg-rose-50 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600'}`}
             >
                <svg className="w-5 h-5" fill={isBookmarked ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" /></svg>
             </button>
             <button onClick={handleBackClick} className="w-10 h-10 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
             </button>
          </div>
        </div>

        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-slate-100 min-h-[400px] mb-6 animate-fadeIn relative overflow-hidden">
          <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>
          <div className="mb-8">
            <div className="flex items-center gap-2 mb-4">
               <span className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-600 bg-blue-50 px-3 py-1 rounded-full">Official Paper</span>
               <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">{currentQ.examName}</span>
            </div>
            <h2 className="text-2xl md:text-3xl font-bold hindi-text leading-relaxed text-slate-800">
              {currentQ.question}
            </h2>
          </div>

          <div className="grid gap-3">
            {(['A', 'B', 'C', 'D', 'E'] as const).map((key) => {
              const isCorrect = isReview && currentQ.correctAnswer === key;
              const isSelected = userAns === key;
              const isWrongSelection = isReview && isSelected && !isCorrect;
              const isLocked = !!userAns && !isReview;

              // REFINEMENT: Clean, neutral initial state. Removed initial blueish borders.
              let cardClasses = "relative w-full p-6 rounded-[1.5rem] border-2 flex items-center gap-5 transition-all text-left group ";

              if (isReview) {
                if (isCorrect) cardClasses += "bg-emerald-50 border-emerald-500 shadow-lg shadow-emerald-50";
                else if (isWrongSelection) cardClasses += "bg-rose-50 border-rose-500 shadow-lg shadow-rose-50";
                else cardClasses += "bg-white border-slate-100 opacity-60";
              } else {
                if (isSelected) cardClasses += "bg-blue-50 border-blue-600 shadow-xl shadow-blue-50";
                else if (isLocked) cardClasses += "bg-slate-50 border-slate-50 opacity-60 grayscale cursor-not-allowed";
                else cardClasses += "bg-white border-slate-100 hover:border-slate-300 active:scale-[0.99]";
              }

              return (
                <button 
                  key={key} 
                  disabled={isLocked || isReview}
                  onClick={() => handleSelect(key)} 
                  className={cardClasses}
                >
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg shrink-0 transition-colors ${
                    isCorrect ? 'bg-emerald-600 text-white' : 
                    isWrongSelection ? 'bg-rose-600 text-white' : 
                    isSelected ? 'bg-blue-600 text-white' : 
                    'bg-slate-100 text-slate-400 group-hover:bg-slate-200 group-hover:text-slate-600'
                  }`}>
                    {key}
                  </div>
                  <span className={`hindi-text font-bold text-xl ${
                    isCorrect ? 'text-emerald-900' : 
                    isWrongSelection ? 'text-rose-900' : 
                    isSelected ? 'text-blue-900' : 
                    'text-slate-600'
                  }`}>
                    {currentQ.options[key]}
                  </span>
                </button>
              );
            })}
          </div>
        </div>

        <div className="flex items-center justify-between mb-12">
           <button 
              onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))}
              disabled={currentIdx === 0}
              className="px-8 py-4 rounded-2xl bg-white border border-slate-200 text-slate-500 font-black text-xs uppercase tracking-widest hover:bg-slate-50 disabled:opacity-30 transition-all flex items-center gap-2"
           >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7"/></svg>
              Previous
           </button>

           <div className="hidden md:flex items-center gap-2">
              {userAns && <div className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 px-5 py-2.5 rounded-full border border-blue-100 shadow-sm animate-fadeIn">Response Locked</div>}
           </div>

           {currentIdx === session.questions.length - 1 ? (
             <button 
                onClick={handleSubmit}
                className="px-10 py-4 rounded-2xl bg-slate-900 text-white font-black text-xs uppercase tracking-[0.2em] hover:bg-slate-800 shadow-xl transition-all"
             >
                Finish Test
             </button>
           ) : (
             <button 
                onClick={() => setCurrentIdx(prev => Math.min(session.questions.length - 1, prev + 1))}
                className="px-8 py-4 rounded-2xl bg-white border border-slate-200 text-blue-600 font-black text-xs uppercase tracking-widest hover:bg-blue-50 transition-all flex items-center gap-2"
             >
                Next
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7"/></svg>
             </button>
           )}
        </div>
      </div>

      <div className="w-full lg:w-80 shrink-0">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 sticky top-24">
          <h3 className="text-sm font-black uppercase tracking-widest text-slate-400 mb-6 px-2">Navigation Map</h3>
          <div className="grid grid-cols-5 gap-2 h-[400px] overflow-y-auto pr-2 custom-scrollbar p-1">
            {session.questions.map((q, idx) => {
              const isAns = !!answers[q.id];
              const isCurrent = idx === currentIdx;
              let dotClass = "w-10 h-10 rounded-xl flex items-center justify-center font-bold text-xs transition-all ";

              if (isReview) {
                const correct = answers[q.id] === q.correctAnswer;
                const skipped = answers[q.id] === 'E' || !answers[q.id];
                if (correct) dotClass += "bg-emerald-500 text-white";
                else if (skipped) dotClass += "bg-slate-100 text-slate-400";
                else dotClass += "bg-rose-500 text-white";
              } else {
                if (isCurrent) dotClass += "ring-4 ring-blue-100 bg-blue-600 text-white shadow-lg";
                else if (isAns) dotClass += "bg-slate-800 text-white";
                else dotClass += "bg-slate-50 text-slate-300 hover:bg-slate-100";
              }

              return (
                <button 
                  key={idx} 
                  onClick={() => setCurrentIdx(idx)}
                  className={dotClass}
                >
                  {idx + 1}
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default QuizEngine;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question,
  User
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [editName, setEditName] = useState('');
  const [editProfilePic, setEditProfilePic] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [selectedSubtopicIdx, setSelectedSubtopicIdx] = useState<number>(-1);

  const [examSearch, setExamSearch] = useState('');
  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUserPhone = localStorage.getItem('rajquiz_currentUser');
    if (savedUserPhone) {
      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      const userData = users[savedUserPhone];
      if (userData) {
        loginUser(savedUserPhone, userData.name, userData.profilePic);
      } else {
        setView(AppView.AUTH);
      }
    } else {
      setView(AppView.AUTH);
    }
  }, []);

  const loginUser = (userPhone: string, userName?: string, profilePic?: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    setCurrentUser({ phone: userPhone, name: userName, profilePic });
    setEditName(userName || '');
    setEditProfilePic(profilePic || null);
    setView(AppView.HOME);

    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const saveProgress = (testId: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const currentProg = userProgress[testId] || 0;
    const newProgress = { ...userProgress, [testId]: Math.max(currentProg, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'instant' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { 
      setLoginError("Account not found."); 
      return; 
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone, user.name, user.profilePic);
    } else { 
      setLoginError("Invalid password."); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) return;
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    users[phone] = { password, name: '', profilePic: '' };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    localStorage.setItem('rajquiz_currentUser', phone);
    loginUser(phone, '', '');
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    const testId = options.testId || `${type}_${title.replace(/\s+/g, '_')}`;
    const cacheKey = `rajquiz_cache_${testId}`;
    const cachedData = localStorage.getItem(cacheKey);

    if (cachedData) {
      const questions = JSON.parse(cachedData);
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0, userAnswers: {}, 
        startTime: Date.now(), durationInMinutes: 60, completed: false, testId
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: 50 });
      localStorage.setItem(cacheKey, JSON.stringify(questions));
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0, userAnswers: {}, 
        startTime: Date.now(), durationInMinutes: 60, completed: false, testId
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      alert("Please connect to internet to load this test for the first time.");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
      const ans = session.userAnswers[q.id];
      if (!ans) { score += MARKING_SCHEME.UNATTEMPTED; unattempted++; }
      else if (ans === 'E') skipped++;
      else if (ans === q.correctAnswer) { score += MARKING_SCHEME.CORRECT; correct++; }
      else { score += MARKING_SCHEME.WRONG; incorrect++; }
    });
    if (session.testId) saveProgress(session.testId, (score / (session.questions.length * 2)) * 100);
    setLastResults({ score, correctCount: correct, incorrectCount: incorrect, skippedCount: skipped, unattemptedCount: unattempted, totalQuestions: session.questions.length, session, timeTaken: "60:00" } as any);
    navigateTo(AppView.SCORECARD);
  };

  const handleLogout = () => {
    localStorage.removeItem('rajquiz_currentUser');
    setIsLoggedIn(false);
    navigateTo(AppView.AUTH);
  };

  const renderBackButton = (target: AppView = AppView.HOME) => (
    <button onClick={() => navigateTo(target)} className="mb-6 flex items-center gap-2 text-slate-400 font-black hover:text-blue-600 transition-colors uppercase tracking-widest text-xs">
      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
      Back
    </button>
  );

  return (
    <Layout 
      onHomeClick={() => navigateTo(AppView.HOME)} 
      onTopicTestsClick={() => navigateTo(AppView.QUIZ_TOPIC_MENU)}
