                           <div className="flex gap-6 items-center">
                              <div className={`w-20 h-20 rounded-[1.5rem] flex items-center justify-center font-black text-3xl shrink-0 ${isAttempted ? 'bg-emerald-50 text-emerald-600' : isCached ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-300'}`}>
