                           <div className={`absolute bottom-0 left-0 h-1.5 ${isAttempted ? 'bg-emerald-500' : 'bg-blue-600'} transition-all group-hover:w-full`} style={{ width: `${progress}%` }}></div>
                        </button>
                     );
                   })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_SUBTOPIC_MENU && selectedGroup && (
             <div className="max-w-5xl mx-auto px-4">
