                    <div key={q.id} className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm relative overflow-hidden">
                       <div className="absolute top-0 left-0 w-1.5 h-full bg-slate-200"></div>
                       <div className="flex items-center gap-3 mb-6">
                          <span className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-sm">{idx + 1}</span>
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{q.examName}</span>
                       </div>
                       <h3 className="text-xl font-bold mb-8 hindi-text text-slate-800">{q.question}</h3>
                       <div className="grid gap-3">
                          {['A','B','C','D','E'].map(key => {
                             const isCorrect = q.correctAnswer === key;
                             return (
                               <div key={key} className={`p-5 rounded-2xl border-2 flex items-center gap-4 ${isCorrect ? 'bg-emerald-50 border-emerald-500 shadow-lg' : 'bg-slate-50 border-slate-50 opacity-60'}`}>
