                            <span className="text-[10px] font-black uppercase tracking-widest text-blue-600 group-hover:translate-x-1 transition-transform">Solve →</span>
                          </div>
                       </button>
                     );
                   })}
                </div>
             </div>
          )}

          {view === AppView.QUIZ_TOPIC_TESTS_MENU && selectedSubtopic && selectedGroup && (
