import { GoogleGenAI, Type } from "@google/genai";
import { Question } from "../types.ts";

/**
 * Fetches Previous Year Questions (PYQs) using Gemini AI.
 * Includes retry logic and optimized prompt structure to avoid 500 RPC proxy errors.
 */
export async function fetchPYQs(params: {
  count: number;
  subject?: string;
  topic?: string;
  isMix?: boolean;
  testNumber?: number;
  examContext?: string;
}, retryCount = 0): Promise<Question[]> {
  const { count, subject, topic, isMix, testNumber, examContext } = params;

  // Re-initialize client to ensure fresh headers/session
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const topicDescriptor = topic || subject || 'Rajasthan General Knowledge';
  const uniquenessKey = isMix ? `MIXED_VERSION_${testNumber}` : `TOPIC_${topicDescriptor}_SET_${testNumber}`;

  // Optimized prompt: simplified and structured to be proxy-friendly
  const prompt = `Task: Generate a JSON array of ${count} unique Rajasthan competitive exam PYQs.
  Context: ${topicDescriptor}. Exam sources: RPSC/RSSB (RAS, CET, LDC, Patwar).
  Language: Standard Hindi.
  Format: Valid JSON only.

  Constraints:
  1. No duplicate questions.
  2. Option 'E' must always be "अनुत्तरित प्रश्न".
  3. Correct answer must be one of A, B, C, D.

  Schema: [{
    "id": "q_${uniquenessKey}_[index]",
    "question": "Hindi text",
    "options": {"A":"..","B":"..","C":"..","D":"..","E":"अनुत्तरित प्रश्न"},
    "correctAnswer": "A",
    "examName": "Exam Name",
    "examYear": 2023,
    "subject": "${topicDescriptor}"
  }]`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        temperature: 0.7,
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: {
                type: Type.OBJECT,
                properties: {
                  A: { type: Type.STRING },
                  B: { type: Type.STRING },
                  C: { type: Type.STRING },
                  D: { type: Type.STRING },
                  E: { type: Type.STRING },
                },
                required: ['A', 'B', 'C', 'D', 'E']
              },
              correctAnswer: { type: Type.STRING },
              examName: { type: Type.STRING },
              examYear: { type: Type.NUMBER },
              subject: { type: Type.STRING },
            },
            required: ['id', 'question', 'options', 'correctAnswer', 'examName', 'examYear', 'subject']
          }
        }
      }
    });

    const text = response.text || "[]";
    return JSON.parse(text.trim()).slice(0, count);
  } catch (error) {
    // Retry logic for transient 500 errors (Error code 6 or status UNKNOWN)
    if (retryCount < 2) {
      console.warn(`Retrying Gemini fetch... Attempt ${retryCount + 1}`);
      // Add a small delay before retry
      await new Promise(r => setTimeout(r, 1000));
      return fetchPYQs(params, retryCount + 1);
    }
    console.error("Gemini PYQ Fetch Error after retries:", error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from './components/Layout.tsx';
import QuizEngine from './components/QuizEngine.tsx';
import ScoreCard from './components/ScoreCard.tsx';
import { 
  AppView, 
  AuthSubView,
  QuizSession, 
  QuizType, 
  QuizResults,
  Question,
  User
} from './types.ts';
import { 
  TOPIC_GROUPS,
  TopicGroup,
  MARKING_SCHEME,
  OFFICIAL_EXAMS
} from './constants.ts';
import { fetchPYQs } from './services/geminiService.ts';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.AUTH);
  const [authStep, setAuthStep] = useState<AuthSubView>(AuthSubView.CHOICE);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [editName, setEditName] = useState('');
  const [editProfilePic, setEditProfilePic] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [activeSession, setActiveSession] = useState<QuizSession | null>(null);
  const [lastResults, setLastResults] = useState<QuizResults | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<TopicGroup | null>(null);
  const [selectedSubtopic, setSelectedSubtopic] = useState<string | null>(null);
  const [selectedSubtopicIdx, setSelectedSubtopicIdx] = useState<number>(-1);

  const [userProgress, setUserProgress] = useState<Record<string, number>>({});
  const [bookmarks, setBookmarks] = useState<Question[]>([]);

  useEffect(() => {
    const savedUserPhone = localStorage.getItem('rajquiz_currentUser');
    if (savedUserPhone) {
      const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
      const userData = users[savedUserPhone];
      if (userData) {
        loginUser(savedUserPhone, userData.name, userData.profilePic);
      } else {
        setView(AppView.AUTH);
      }
    } else {
      setView(AppView.AUTH);
    }
  }, []);

  const loginUser = (userPhone: string, userName?: string, profilePic?: string) => {
    setIsLoggedIn(true);
    setPhone(userPhone);
    const userData: User = { phone: userPhone, name: userName, profilePic };
    setCurrentUser(userData);
    setEditName(userName || '');
    setEditProfilePic(profilePic || null);
    setView(AppView.HOME);

    const progressKey = `rajquiz_progress_${userPhone}`;
    const savedProgress = localStorage.getItem(progressKey);
    if (savedProgress) {
      try { setUserProgress(JSON.parse(savedProgress)); } catch (e) { console.error(e); }
    }

    const bookmarkKey = `rajquiz_bookmarks_${userPhone}`;
    const savedBookmarks = localStorage.getItem(bookmarkKey);
    if (savedBookmarks) {
      try { setBookmarks(JSON.parse(savedBookmarks)); } catch (e) { console.error(e); }
    }
  };

  const handleProfileUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const updatedUser = { 
      ...users[currentUser.phone], 
      name: editName, 
      profilePic: editProfilePic 
    };
    users[currentUser.phone] = updatedUser;

    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    setCurrentUser({ ...currentUser, name: editName, profilePic: editProfilePic || '' });
    setView(AppView.PROFILE);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Limit file size for localStorage (approx 500KB)
      if (file.size > 512 * 1024) {
        alert("कृपया छोटी फोटो चुनें (Max 500KB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditProfilePic(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveProgress = (testId: string, percentage: number) => {
    const progressKey = `rajquiz_progress_${phone}`;
    const currentProg = userProgress[testId] || 0;
    const newProgress = { ...userProgress, [testId]: Math.max(currentProg, percentage) };
    setUserProgress(newProgress);
    localStorage.setItem(progressKey, JSON.stringify(newProgress));
  };

  const toggleBookmark = (question: Question) => {
    const isBookmarked = bookmarks.some(b => b.id === question.id);
    let newBookmarks;
    if (isBookmarked) {
      newBookmarks = bookmarks.filter(b => b.id !== question.id);
    } else {
      newBookmarks = [...bookmarks, question];
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`rajquiz_bookmarks_${phone}`, JSON.stringify(newBookmarks));
  };

  const navigateTo = (newView: AppView) => {
    setView(newView);
    window.scrollTo({ top: 0, behavior: 'instant' });
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    const user = users[phone];
    if (!user) { 
      setAuthStep(AuthSubView.SIGNUP);
      setLoginError(''); 
      return; 
    }
    if (user.password === password) {
      localStorage.setItem('rajquiz_currentUser', phone);
      loginUser(phone, user.name, user.profilePic);
    } else { 
      setLoginError("गलत पासवर्ड।"); 
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length < 10) return;
    const users = JSON.parse(localStorage.getItem('rajquiz_users') || '{}');
    if (users[phone]) {
      setLoginError("यह नंबर पहले से रजिस्टर है।");
      setAuthStep(AuthSubView.LOGIN);
      return;
    }
    users[phone] = { password, name: '', profilePic: '' };
    localStorage.setItem('rajquiz_users', JSON.stringify(users));
    localStorage.setItem('rajquiz_currentUser', phone);
    loginUser(phone, '', '');
  };

  const startQuiz = useCallback(async (type: QuizType, title: string, options: any = {}) => {
    const testId = options.testId || `${type}_${title.replace(/\s+/g, '_')}`;
    const cacheKey = `rajquiz_cache_${testId}`;
    const cachedData = localStorage.getItem(cacheKey);

    if (cachedData) {
      const questions = JSON.parse(cachedData);
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0, userAnswers: {}, 
        startTime: Date.now(), durationInMinutes: 60, completed: false, testId
      } as any);
      navigateTo(AppView.QUIZ_ACTIVE);
      return;
    }

    setLoading(true);
    try {
      const questions = await fetchPYQs({ ...options, count: 50 });
      localStorage.setItem(cacheKey, JSON.stringify(questions));
      setActiveSession({
        type, title, questions, currentQuestionIndex: 0, userAnswers: {}, 
        startTime: Date.now(), durationInMinutes: 60, completed: false, testId
      } as any);
      setLoading(false);
      navigateTo(AppView.QUIZ_ACTIVE);
    } catch (err) {
      console.error(err);
      alert("सर्वर से कनेक्ट करने में त्रुटि हुई। कृपया पुन: प्रयास करें।");
      setLoading(false);
    }
  }, []);

  const onQuizComplete = (session: any) => {
    let score = 0, correct = 0, incorrect = 0, skipped = 0, unattempted = 0;
    session.questions.forEach((q: any) => {
